from sklearn.neighbors import NearestNeighbors

def compute_target_gradients(X, y, k=None):
    """
    Unified Sobolev target-gradient estimator.

    Dispatches to the appropriate method based on input dimensionality:
      - 1-D: finite differences on the sorted (x, y) pairs — exact and fast.
      - N-D (n_features >= 2): KNN local-linear regression, which estimates
        the full Jacobian vector ∂y/∂x_j for every point simultaneously.

    Returns
    -------
    grads : ndarray, shape (N, D)
        Estimated partial derivatives dy/dx_j at each training point.
        For 1-D output grads[:, 0] is the ordinary derivative.
    """
    if k is None:
        k = SOBOLEV_KNN_K
    N, D = X.shape
    if D == 1:
        # 1-D: sort by x, use np.gradient (central differences), then unsort.
        order   = np.argsort(X[:, 0])
        x_sorted = X[order, 0]
        y_sorted = y[order]
        dy_dx    = np.gradient(y_sorted, x_sorted)
        grads    = np.empty((N, 1), dtype=np.float64)
        grads[order, 0] = dy_dx
        return np.clip(np.nan_to_num(grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)
    else:
        return compute_multivariate_target_gradients(X, y, k=k)


def compute_multivariate_target_gradients(X, y, k=15):
    """
    Estimates dy/dx for unstructured multivariate data using local linear regression.
    Works natively for 1D, 2D, and ND datasets.

    Fully vectorised using batched normal equations with Tikhonov regularisation:
        g_i = (X_local^T X_local + λI)^{-1} X_local^T y_local
    for each point i, solved in a single batched np.linalg.solve call — O(N·D³)
    instead of O(N) Python-level lstsq calls.  For D≤~15 and N≤50 000 this is
    typically 10-50× faster than the loop version.
    """
    N, D = X.shape
    k = min(k, N)

    nbrs = NearestNeighbors(n_neighbors=k).fit(X)
    _, indices = nbrs.kneighbors(X)

    # Build centred neighbourhoods: (N, K, D) and (N, K)
    X_local = X[indices] - X[:, np.newaxis, :]   # (N, K, D)
    y_local = y[indices] - y[:, np.newaxis]       # (N, K)

    # Normal equations: (N, D, D) @ g = (N, D)
    XTX = np.einsum('nkd,nke->nde', X_local, X_local)   # (N, D, D)
    XTy = np.einsum('nkd,nk->nd',  X_local, y_local)    # (N, D)

    # Tikhonov regularisation: λ = 1e-6 × mean diagonal (scale-adaptive ridge)
    diag_mean = XTX.reshape(N, -1)[:, ::D + 1].mean(axis=1).clip(min=1e-8)
    lam = 1e-6 * diag_mean                               # (N,)
    eye = np.eye(D, dtype=X.dtype)[np.newaxis]           # (1, D, D)
    XTX += lam[:, np.newaxis, np.newaxis] * eye

    try:
        target_grads = np.linalg.solve(XTX, XTy[..., np.newaxis])[..., 0]   # (N, D)
    except np.linalg.LinAlgError:
        # Singular batches: fall back to per-point lstsq (rare, small N)
        target_grads = np.zeros((N, D), dtype=np.float64)
        for i in range(N):
            g, _, _, _ = np.linalg.lstsq(X_local[i], y_local[i], rcond=None)
            target_grads[i] = g

    return np.clip(np.nan_to_num(target_grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)
def evaluate_tree_gradients(tree, X, affine_a, eps=1e-5):
    """
    Computes the gradient of the CGP tree w.r.t each input feature using central differences.
    """
    N, D = X.shape
    grads = np.zeros((N, D))
    
    for j in range(D):
        X_plus = X.copy()
        X_plus[:, j] += eps
        y_plus = tree.evaluate(X_plus)
        
        X_minus = X.copy()
        X_minus[:, j] -= eps
        y_minus = tree.evaluate(X_minus)
        
        # Don't forget the affine scaling applies to the derivative too!
        # d/dx (a * f(x) + b) = a * f'(x)
        raw_grad = (y_plus - y_minus) / (2 * eps)
        grads[:, j] = affine_a * raw_grad

    # Sanitize to prevent explosions from polluting the loss
    return np.clip(np.nan_to_num(grads, nan=0.0, posinf=1e5, neginf=-1e5), -1e5, 1e5)


def _multiclass_sample_weights(yg, mode=None):
    """
    Per-sample weights for a one-hot multi-class label matrix `yg` (N, K).

    Returns an (N,) array whose mean is 1.0 (so the over-all loss scale stays
    comparable to the unweighted case), with each sample weighted inversely to
    its true class's empirical frequency.

    Returns None when class-weighting is disabled (mode='none' or
    CLASS_WEIGHT_ENABLED is False).
    """
    if yg is not None and len(yg.shape) == 1:
        yg = np.eye(2)[yg.astype(int)]
    if mode is None:
        mode = CLASS_WEIGHT_MODE
    if (not CLASS_WEIGHT_ENABLED) or mode == 'none' or yg is None:
        return None
    counts = yg.sum(axis=0)  # (K,)
    K = yg.shape[1]
    # Guard against zero-count classes in this batch.
    # We replace zero counts with 1.0 to avoid division by zero. Since the class
    # is not present in the batch, it will not be accessed by `sw = cls_w[true_cls]`.
    if not np.all(counts > 0):
        counts = np.where(counts == 0, 1.0, counts)
    N = float(yg.shape[0])
    if mode == 'balanced':
        cls_w = N / (K * counts)
    elif mode == 'sqrt_balanced':
        cls_w = np.sqrt(N / (K * counts))
    else:
        return None
    true_cls = np.argmax(yg, axis=1)
    sw = cls_w[true_cls]
    # Re-normalise to mean 1.0 (defensive — the formulas above already do this
    # under exact label counts, but minibatches can drift)
    m = float(np.mean(sw))
    if m > 1e-12:
        sw = sw / m
    return sw


def _binary_sample_weights(y_eval, mode=None):
    """
    Per-sample weights for a binary target vector `y_eval` (treated as 0/1).
    Mean is normalised to 1.0.  Returns None when weighting is disabled or the
    batch is degenerate (all-one-class).
    """
    if mode is None:
        mode = CLASS_WEIGHT_MODE
    if (not CLASS_WEIGHT_ENABLED) or mode == 'none' or y_eval is None:
        return None
    y_bin = (np.asarray(y_eval) >= 0.5).astype(np.float64)
    n_pos = float(y_bin.sum())
    n_neg = float(len(y_bin) - n_pos)
    if n_pos < 1.0 or n_neg < 1.0:
        # Degenerate batch — no minority class present.  Skip weighting so we
        # don't divide by zero or amplify noise.
        return None
    N = float(len(y_bin))
    if mode == 'balanced':
        w_pos, w_neg = N / (2.0 * n_pos), N / (2.0 * n_neg)
    elif mode == 'sqrt_balanced':
        w_pos = np.sqrt(N / (2.0 * n_pos))
        w_neg = np.sqrt(N / (2.0 * n_neg))
    else:
        return None
    sw = y_bin * w_pos + (1.0 - y_bin) * w_neg
    m = float(np.mean(sw))
    if m > 1e-12:
        sw = sw / m
    return sw


# ==========================================
# PER-EXAMPLE DIFFICULTY WEIGHTING (hard-example mining)
# ==========================================
# Process-local state for the optional INSTANCE_REWEIGHT_* feature (see the
# config block for the full rationale).  Each evolution worker keeps its own
# weight vectors, so on Linux fork the parent's config flags are inherited while
# the weights accumulate independently inside every worker process:
#   _DIFFICULTY_ACTIVE  : the (N,) weight vector for the chunk currently being
#                         evaluated, or None when the feature is inactive.  Read
#                         by calculate_fitness / get_case_errors.  Stays None in
#                         the parent process, so parent-side evaluations (init,
#                         HoF re-scoring, validation) always use the TRUE loss.
#   _DIFFICULTY_BY_SIG  : target-fingerprint -> persistent (N,) weight vector,
#                         so the weights a worker builds for one output survive
#                         across the successive chunks it runs on that output.
_DIFFICULTY_ACTIVE = None
_DIFFICULTY_BY_SIG = {}


def _difficulty_target_sig(y_target):
    """Stable digest of a target vector, used to key its difficulty weights.

    Same blake2b-over-bytes scheme as the fitness cache, so two different
    outputs (or two gradient-boosting residual targets) never share a weight
    vector while the same output across chunks always does.
    """
    arr = np.ascontiguousarray(y_target)
    return (arr.shape, str(arr.dtype),
            hashlib.blake2b(arr.tobytes(), digest_size=16).digest())


def _difficulty_active_weights(n_rows, batch_indices=None):
    """Raw per-row difficulty weights for the rows being evaluated, or None.

    Returns ``_DIFFICULTY_ACTIVE`` sliced to the current evaluation when the
    feature is active and the vector lines up with the data; otherwise None.
    Weights are returned UN-normalised — callers fold them into the existing
    class / sample weights and renormalise so the loss scale is preserved.
    """
    if not INSTANCE_REWEIGHT_ENABLED:
        return None
    w = _DIFFICULTY_ACTIVE
    if w is None:
        return None
    try:
        if batch_indices is not None:
            bi = np.asarray(batch_indices)
            if bi.size == 0 or int(bi.max()) >= len(w):
                return None
            return w[bi]
        if len(w) != n_rows:
            return None
        return w
    except Exception:
        return None


def _difficulty_sel_extra(per_row, base_w, dw):
    """Selection-only loss delta contributed by the difficulty weights.

    Given a per-row loss (e.g. BCE / softmax-CE), the existing per-row weight
    ``base_w`` (class weights, or None) and the raw difficulty weights ``dw``,
    return ``weighted_mean − base_mean``.  Adding this to the raw loss yields
    the SELECTION loss while leaving the HoF-keyed raw loss untouched.  Both
    means use mean-1-normalised weights so only the *relative* emphasis moves.
    """
    base = float(np.mean(per_row if base_w is None else base_w * per_row))
    comb = dw if base_w is None else (base_w * dw)
    m = float(np.mean(comb))
    if m <= 1e-12:
        return 0.0
    comb = comb / m
    return float(np.mean(comb * per_row)) - base


def _difficulty_begin(y_target):
    """Activate the difficulty-weight vector for one worker chunk.

    Looks up (or lazily creates, initialised to 1.0) the persistent weight
    vector for THIS target inside the current worker process and points
    ``_DIFFICULTY_ACTIVE`` at it, so weights accumulate across the successive
    chunks a worker runs on the same output.  Clears the pointer (so every
    downstream evaluation no-ops) when the feature is off.
    """
    global _DIFFICULTY_ACTIVE
    if not INSTANCE_REWEIGHT_ENABLED:
        _DIFFICULTY_ACTIVE = None
        return
    try:
        n = len(y_target)
        sig = _difficulty_target_sig(y_target)
        w = _DIFFICULTY_BY_SIG.get(sig)
        if w is None or len(w) != n:
            w = np.ones(n, dtype=np.float64)
            _DIFFICULTY_BY_SIG[sig] = w
        _DIFFICULTY_ACTIVE = w
    except Exception:
        _DIFFICULTY_ACTIVE = None


def _difficulty_failures(ind, X, y_target, type_code,
                         bg_logits=None, class_idx_in_group=None, Y_group=None):
    """Boolean (N,) mask — True where ``ind`` currently mis-predicts the row.

    Classification (binary / softmax group) → the predicted class is wrong.
    Regression → the residual exceeds INSTANCE_REWEIGHT_REG_TOL × std(y), a
    scale-free "not close enough".  Mirrors the prediction path used by
    calculate_fitness so "failure" matches what is actually being optimised.
    """
    preds = ind.tree.evaluate(X)
    preds = np.clip(np.nan_to_num(preds, nan=0.0, posinf=1e9, neginf=-1e9), -1e9, 1e9)
    if bg_logits is not None:
        logits = bg_logits.copy()
        logits[:, class_idx_in_group] = preds
        return np.argmax(logits, axis=1) != np.argmax(Y_group, axis=1)
    if type_code == 6:
        pred_pos = (1.0 / (1.0 + np.exp(-preds))) >= 0.5
        return pred_pos != (y_target >= 0.5)
    a = getattr(ind, 'affine_a', 1.0)
    b = getattr(ind, 'affine_b', 0.0)
    preds = a * preds + b
    for corr_tree, ca, cb, lr in getattr(ind, 'boost_stages', []):
        corr = corr_tree.evaluate(X)
        corr = np.clip(np.nan_to_num(corr, nan=0.0, posinf=1e9, neginf=-1e9), -1e9, 1e9)
        preds = preds + lr * (ca * corr + cb)
    tol = INSTANCE_REWEIGHT_REG_TOL * (float(np.std(y_target)) + 1e-12)
    return np.abs(preds - y_target) > tol


def _difficulty_update(population, X, y_target, type_code, gen,
                       bg_logits=None, class_idx_in_group=None, Y_group=None):
    """Grow the difficulty weight of every example the champion fails.

    Called once per generation from inside a worker's evolution loop.  "The
    model" is the current lowest-TRUE-loss individual; each example it
    mis-predicts has its weight multiplied by (1 + INSTANCE_REWEIGHT_INCREMENT)
    and the whole vector is clamped to [1.0, INSTANCE_REWEIGHT_MAX] so a
    permanent outlier can't grow without bound.  Fully guarded: a no-op when
    the feature is off, the vector is misaligned, or anything goes wrong.
    """
    if not INSTANCE_REWEIGHT_ENABLED or _DIFFICULTY_ACTIVE is None:
        return
    if INSTANCE_REWEIGHT_UPDATE_EVERY > 1 and (gen % INSTANCE_REWEIGHT_UPDATE_EVERY) != 0:
        return
    w = _DIFFICULTY_ACTIVE
    if len(w) != len(X):
        return
    try:
        finite = [ind for ind in population
                  if np.isfinite(ind.loss) and ind.loss < 1e9]
        if not finite:
            return
        champ = min(finite, key=lambda x: x.loss)
        fail = _difficulty_failures(champ, X, y_target, type_code,
                                    bg_logits, class_idx_in_group, Y_group)
        if fail.shape[0] != len(w):
            return
        w[fail] *= (1.0 + INSTANCE_REWEIGHT_INCREMENT)
        np.clip(w, 1.0, INSTANCE_REWEIGHT_MAX, out=w)
    except Exception:
        pass


# ==========================================
# DATA-SCALE HINT & TYPE-COERCION HELPERS
# ==========================================
# Dataset-scale hint set once during train_mode after preprocessing.  Used by
# the constant optimiser to size DE bounds, by mutation operators to generate
# new constants on the right order of magnitude, and by _random_const to seed
# initial populations near plausible scales.  Without this, a dataset whose
# answer involves constants like 700_000 or 30 is unreachable from the default
# magnitudes (gauss(0, 2) * 1000 ≈ 6000 maximum).
_DATA_SCALE_HINT = 10.0

def _set_data_scale_hint(X, Y):
    """Set the module-level _DATA_SCALE_HINT from training data."""
    global _DATA_SCALE_HINT
    try:
        parts = []
        if X is not None and getattr(X, 'size', 0) > 0:
            xa = np.abs(np.asarray(X, dtype=float))
            xa = xa[np.isfinite(xa)]
            if xa.size > 0:
                parts.append(float(np.max(xa)))
        if Y is not None and getattr(Y, 'size', 0) > 0:
            ya = np.abs(np.asarray(Y, dtype=float))
            ya = ya[np.isfinite(ya)]
            if ya.size > 0:
                parts.append(float(np.max(ya)))
        if parts:
            s = max(parts)
            if np.isfinite(s) and s > 0:
                _DATA_SCALE_HINT = max(10.0, s)
    except Exception:
        pass
    return _DATA_SCALE_HINT


# Tokens recognised as boolean values when a user picks a numeric type on an
# object/string column.  Case-insensitive.  Y/N and 1/0 are included so binary
# survey-style data ("Y", "N") and 0/1 strings ("0", "1") all collapse to
# clean 0.0/1.0 numerics without needing one-hot encoding.
_BOOLEAN_TRUE_TOKENS  = frozenset({'true',  't', 'yes', 'y'})
_BOOLEAN_FALSE_TOKENS = frozenset({'false', 'f', 'no',  'n'})

def _detect_boolean_like_column(col_data):
    """
    Inspect *col_data* (object/string column).  If every non-null value is one
    of True/False or Yes/No/Y/N (case-insensitive), return
    ``(True, true_tokens, false_tokens)`` describing which tokens map to 1
    and which to 0.  Otherwise return ``(False, None, None)``.
    """
    try:
        s = pd.Series(col_data)
        s = s[s.notna()]
        if len(s) == 0:
            return False, None, None
        tokens = set(str(v).strip().lower() for v in s.values)
        if not tokens:
            return False, None, None
        if tokens.issubset({'true', 'false'}):
            return True, {'true'}, {'false'}
        if tokens.issubset({'t', 'f'}):
            return True, {'t'}, {'f'}
        # Yes/No (allow Y and N mixed with Yes and No)
        if tokens.issubset({'yes', 'no', 'y', 'n'}):
            return True, {'yes', 'y'}, {'no', 'n'}
        return False, None, None
    except Exception:
        return False, None, None


def _convert_boolean_column_to_numeric(col_data, true_tokens, false_tokens):
    """
    Map each entry of *col_data* to 1.0 if it matches *true_tokens*, 0.0 if
    it matches *false_tokens*, NaN otherwise (preserves missing values so the
    downstream imputer can decide how to fill them).
    """
    out = np.full(len(col_data), np.nan, dtype=float)
    for i, v in enumerate(col_data):
        if v is None:
            continue
        # pd.isna handles both None and float NaN; guard against array-likes.
        try:
            if pd.isna(v):
                continue
        except (TypeError, ValueError):
            pass
        s = str(v).strip().lower()
        if s in true_tokens:
            out[i] = 1.0
        elif s in false_tokens:
            out[i] = 0.0
    return out


def _is_object_like_dtype(dtype):
    """
    True if *dtype* is non-numeric and holds strings/mixed values.  Handles
    both numpy ``object`` arrays (pandas <2.x default) and the modern pandas
    ``string`` / StringArray dtype.  ``dtype == object`` alone misses the
    latter on pandas ≥ 2.0.
    """
    try:
        if pd.api.types.is_numeric_dtype(dtype):
            return False
        if pd.api.types.is_bool_dtype(dtype):
            return False
        if pd.api.types.is_datetime64_any_dtype(dtype):
            return False
        # Catch object, string, category, and the generic 'O' kind.
        if pd.api.types.is_string_dtype(dtype):
            return True
        if hasattr(dtype, 'kind') and dtype.kind == 'O':
            return True
        return False
    except Exception:
        return False


def _column_is_mostly_numeric(col_data, threshold=0.8):
    """
    Return True if at least *threshold* of the non-null values in *col_data*
    can be parsed as numbers via pd.to_numeric.  Used to decide whether an
    object-dtype column the user marked as numeric is genuinely numeric
    (stored as strings like '1.5') vs. truly categorical strings.
    """
    try:
        s = pd.Series(col_data)
        n_non_null = int(s.notna().sum())
        if n_non_null == 0:
            return True
        parsed = pd.to_numeric(s, errors='coerce')
        return int(parsed.notna().sum()) / n_non_null >= threshold
    except Exception:
        return False


# --- CONFIGURATION ---
POPULATION_SIZE = 200
TOURNAMENT_SIZE = 20
MAX_COMPLEXITY = 2500
HOF_SIZE = 10
COST_CONST = .0
COST_VAR = 0.
COST_OP_SIMPLE = 2.0
COST_OP_COMPLEX = 4.0
COST_UNARY_RISK = 3.0
COST_UNARY_SAFE = 3.0
COST_UNARY_CHEAP = 1.0
# Comparison/if_else costs: kept low so the search isn't punished for
# discovering piecewise structures.  A typical Diode-style answer
# IF(x > c) THEN x ELSE 0 needs gt(3 → 2) + const + if_else(10 → 3) ≈ 5
# vs. a smooth approximation (relu+max+tanh) ≈ 12.  Without lowering these,
# parsimony pressure made smooth approximations win even when the exact
# piecewise answer was discoverable.
COST_IF = 3.0
COST_COMPARISON = 2.0   # gt, lt, gte, lte comparison operators

# ---- IF/ELSE Branching ----
# When enabled, adds comparison operators (gt, lt, gte, lte) and a ternary
# if_else node to the CGP graph.  This creates a hybrid CGP + decision tree
# where conditions can compare constants to variables, variables to variables,
# or entire sub-expressions to each other.  Branches can output constants,
# 0/1 booleans, or the result of arbitrary sub-expressions.
IF_ELSE_ENABLED = False   # toggled interactively at startup

# ---- Differentiable Branching ----
# When enabled alongside IF/ELSE, the hard np.where(cond > 0.5, true, false)
# is replaced by a smooth sigmoid blend:
#   result = σ(k*(cond - 0.5)) * true + (1 - σ(k*(cond - 0.5))) * false
# This makes the branch differentiable w.r.t. the condition, which helps
# constant optimisation (Nelder-Mead / L-BFGS-B can smooth-gradient through
# branches) and produces smoother ensemble predictions in gradient boosting.
# The steepness k controls the transition sharpness:
#   k=10  → fairly soft (≈95% hard at ±0.2 from threshold)
#   k=20  → moderately sharp (default, good balance)
#   k=50  → nearly hard (≈99.99% at ±0.1 from threshold)
DIFFERENTIABLE_BRANCHING   = False  # toggled interactively at startup
DIFF_BRANCH_STEEPNESS      = 20.0   # sigmoid steepness k

# ---- Gradient Boosting ----
# When enabled, runs multiple sequential CGP evolution stages.  After each
# stage the best model's predictions are subtracted from the target (residuals),
# and the next stage evolves on those residuals.  Final prediction is the sum
# of all stage models, weighted by a learning rate.  Inspired by XGBoost /
# gradient boosting machines.  Works with or without IF/ELSE nodes.
# Now supports CLASSIFICATION (binary + multi-class) via logistic / softmax
# pseudo-residuals, mirroring how XGBoost handles log-loss.
GRADIENT_BOOSTING_ENABLED  = False   # toggled interactively at startup
GRADIENT_BOOSTING_STAGES   = 5      # number of boosting rounds
GRADIENT_BOOSTING_LR       = 0.3    # learning rate (shrinkage)
GRADIENT_BOOSTING_GENS     = 2000   # generations per boosting stage
GRADIENT_BOOSTING_SUBSAMPLE = 1.0   # fraction of rows sampled per stage (stochastic GB)
GRADIENT_BOOSTING_LR_DECAY  = 1.0   # multiplicative LR decay per stage (1.0 = no decay)
GRADIENT_BOOSTING_L2_LEAF   = 0.0   # L2 regularisation on stage predictions (0 = none)
GRADIENT_BOOSTING_DART_DROP = 0.0   # DART: probability of dropping a previous stage (0 = off)
GRADIENT_BOOSTING_PATIENCE  = 3     # early-stop patience (val R² / accuracy stalls)
GRADIENT_BOOSTING_HESSIAN   = True  # 2nd-order (Hessian-weighted) fitness for boosting stages

# Whitelist of allowed operations during evolution.
# This is set interactively at runtime via select_allowed_ops().
ALLOWED_OPS = ['+', '-', '*', '/', 'pow', 'exp', 'log', 'const']  # default fallback

# Default CGP Settings
CGP_NODES = 50
CGP_MUT_RATE = 3

# Self-adaptive sigma bounds and meta-learning rate
SIGMA_TAU = 0.15     # meta-learning rate for self-adaptive mutation
SIGMA_MIN = 0.5
SIGMA_MAX = 20.0

# Parsimony pressure coefficient: multiplied by complexity and added to fitness.
# Higher values favour simpler (shorter) expressions more aggressively.
# 0.0 = no parsimony; 0.01 = gentle; 0.05 = moderate; 0.2+ = strong.
# In the "linear" parsimony model this is the additive coefficient; in the
# "mdl" model it is unused (MDL_COMPLEXITY_BITS plays its role instead).
PARSIMONY_STRENGTH = 0.01

# ---- Parsimony model ----
# Chooses HOW complexity is traded against fit to form the *selection* fitness
# used by parent selection, simulated-annealing acceptance and the AFPO
# Pareto-trim.  Crucially this only shapes which structures evolution explores:
# the Hall of Fame is keyed on raw loss / accuracy and the final model is picked
# by the PySR knee score (`compute_pysr_scores` / `get_best_overall`), so the
# parsimony model can never make the *reported* model worse than the frontier
# already contains — it only steers the search.
#
#   "linear" : fitness = loss + (PARSIMONY_STRENGTH + freq_adj)·complexity   [legacy]
#       The classic additive penalty.  This engine's loss is already
#       variance-normalised (≈1 for the mean predictor, →0 for a perfect fit),
#       so the coefficient is roughly problem-independent — but the *shape* is
#       wrong: once the loss is small the k·complexity term dominates, so a
#       near-perfect but slightly larger model can score WORSE than a terrible
#       tiny one.  This is the well-known linear-parsimony pathology.
#
#   "mdl"    : fitness = ½·MDL_DATA_WEIGHT·log2(loss)
#                       + (MDL_COMPLEXITY_BITS + freq_adj)·complexity        [default]
#       Minimum Description Length (information-theoretic Occam).  The data term
#       is the Gaussian code length of the residuals, so each *relative* halving
#       of the loss is worth a fixed number of bits regardless of absolute
#       scale.  Added complexity is paid for in bits and only wins if it buys at
#       least that many bits of fit, which removes the small-loss pathology: a
#       model many halvings better in loss can always justify a few extra
#       complexity-bits.  This is the trade-off AIFeynman 2.0 and the Bayesian
#       Machine Scientist use, and is the recommended default.
PARSIMONY_MODE = "mdl"

# MDL data-term weight — acts like an effective (soft) sample size on the
# residual code length ½·w·log2(loss).  Larger ⇒ fit matters more relative to
# complexity (the "more data ⇒ complexity is cheaper" regime); smaller ⇒
# stronger Occam pressure.  Because the selection fitness also drives the
# simulated-annealing acceptance test (exp(-Δfitness/T)), w sets BOTH the
# accuracy↔complexity trade (via the bits/w ratio) AND how greedy annealing is
# (via the absolute magnitude).  Too small (w≈1) over-prunes early exploration
# on structure-building targets (sin/cos frequencies collapse to a flat fit);
# 3.0 keeps enough fit-pull to grow real structure while still simplifying.
# Chosen for robustness on bench_denovo: across two independent 5-seed sweeps
# of the regression suite, w=3.0 with the bits below matched-or-beat the legacy
# linear penalty on median R² on BOTH sweeps at comparable median complexity
# (a higher-w/lower-bits setting reached a better peak but dipped below linear
# on one sweep, so the steadier setting is the default).
MDL_DATA_WEIGHT     = 3.0
# MDL model-term cost in *bits per unit of the existing complexity measure*.
# This is the "mdl" analogue of PARSIMONY_STRENGTH.  With MDL_DATA_WEIGHT=3.0
# the bits/w ratio (~0.0083) makes one halving of the loss worth ~60 complexity
# units — gentle Occam pressure that, unlike the linear penalty, stays constant
# as the loss shrinks instead of swamping it.
MDL_COMPLEXITY_BITS = 0.025

# ---- MDL constant cost (description length of the fitted constants) ----
# The complexity measure above prices OPERATORS (COST_CONST is 0.0, so constants
# are structurally free).  But a model that threads the data with a fistful of
# high-precision magic numbers is *not* parsimonious — those constants are real
# parameters that have to be described, exactly the term BIC / AIFeynman / the
# Bayesian Machine Scientist add on top of the structural cost.  This charges
# each active constant a cost on the SAME operator-cost currency as the
# structural complexity, so it is automatically priced by the same per-unit
# coefficient (bit_cost in MDL mode, PARSIMONY_STRENGTH in linear mode) and
# stays on-scale with the existing, deliberately-gentle complexity axis instead
# of swamping it the way a textbook ½·log2(N) BIC term would:
#
#     cost(c) = MDL_CONST_BASE_COST + log2(1 + (c / scale)**2) / 2
#
# — a fixed cost per parameter (≈ a simple operator) plus a gentle, magnitude-
# aware precision surcharge (~free near the target's own scale, a few units for
# a wild outlier), capped per constant at MDL_CONST_MAX_COST.  It is folded into
# the complexity term INSIDE parsimony_fitness only, never into the HoF-keyed
# raw loss or the Pareto `complexity` axis, so it is purely selection-only: the
# reported frontier is unchanged and it merely nudges the search toward
# equivalent forms that lean on fewer / rounder constants.  ENABLED=False
# recovers the exact prior behaviour (constants free).
MDL_CONST_BITS_ENABLED = True
MDL_CONST_BASE_COST    = 2.0    # per-constant cost in operator-cost units (≈ COST_OP_SIMPLE)
MDL_CONST_SCALE        = 1.0    # value scale (× std(y)) below which a constant's
                                # precision surcharge is ~free
MDL_CONST_MAX_COST     = 8.0    # per-constant cap so one outlier can't dominate

# ---- Adaptive operator costs (dynamic OP_COSTS) ----
# Turn the hand-authored OP_COSTS table (defined further below) from fixed magic
# numbers into a *learned* table that re-prices each operator from how useful it
# proves on the current target as the run progresses (MDL operator code-length;
# see the `AdaptiveOperatorCosts` class).  The intuition: the authored costs are
# a good *prior*, but the right price for an operator is problem- and stage-
# dependent — on a target that genuinely needs `sin`, charging `sin` a flat
# premium for the whole run keeps fighting the search, while on a target that
# never benefits from `exp`, a flat price lets `exp` keep bloating trees.  So
# every few generations each operator is re-priced from the current elite:
# operators the best individuals keep using get cheaper (a shorter code word),
# operators they avoid get pricier.  This is the per-OPERATOR analogue of the
# population-level PySR complexity-frequency adjustment already used here.
#
# The adaptation is deliberately conservative so it can be the default without
# disturbing the finely-tuned complexity scale:
#   • Prior-centred  — with no signal the target IS the authored cost exactly,
#                      so generation-0 behaviour is identical to the static table.
#   • Dirichlet- and EMA-smoothed — sparse/early evidence barely moves a price.
#   • Clamped + mean-preserving — every price stays in a band around its prior
#                      and the table's mean is pinned to the prior mean, so only
#                      *relative* prices move and MAX_COMPLEXITY / the MDL bits
#                      stay calibrated; no operator can collapse to 0 or explode.
# Set ADAPTIVE_COSTS_ENABLED = False to recover the original static table exactly.
ADAPTIVE_COSTS_ENABLED       = True
ADAPTIVE_COST_UPDATE_EVERY   = 25     # generations between re-pricings (per island)
ADAPTIVE_COST_PRIOR_STRENGTH = 50.0   # Dirichlet pseudo-counts (higher ⇒ slower drift from prior)
ADAPTIVE_COST_EMA            = 0.25   # EMA step toward the new target each update
ADAPTIVE_COST_BETA           = 1.0    # repricing exponent (1 = full MDL ratio; <1 = gentler)
ADAPTIVE_COST_ELITE_FRAC     = 0.5    # top fraction (by fitness) counted as "the elite"
ADAPTIVE_COST_MIN_RATIO      = 0.34   # price floor as a fraction of the prior price
ADAPTIVE_COST_MAX_RATIO      = 3.0    # price ceiling as a multiple of the prior price
ADAPTIVE_COST_MIN_POP        = 8      # need at least this many finite-fitness inds to update

# ---- Adaptive-cost refinements (sharper / steadier / more representative) ----
# Four composable upgrades to the re-pricing above, each prior-anchored and
# guarded so it degrades to the previous behaviour when switched off:
#
#  • FITNESS-WEIGHTED usage — the elite are not equal.  Instead of counting each
#    elite occurrence as 1, weight it by how GOOD the carrier is (softmax over
#    fitness), so the very best individuals drive the economy harder than the
#    median elite.  Sharper signal, same prior-centring (uniform weights ⇒ the
#    old plain counts exactly).
#  • MARGINAL-UTILITY (lift) — frequency alone can't tell a load-bearing rare
#    operator from a common-but-redundant one.  Add a bounded correction from the
#    merit GAP between elite that use an operator and elite that don't: ops whose
#    users out-perform the non-users get an extra discount, ops whose users
#    under-perform get a surcharge — on top of the frequency term, before the
#    same clamp + mean-preservation.
#  • BAND ANNEALING — early in a chunk prices may roam the full band to find the
#    right economy; late in a chunk the band narrows toward the prior so the
#    complexity axis stops drifting under final selection (mirrors the SA cosine
#    schedule, which is likewise per-chunk).  No progress signal ⇒ full band.
#  • GLOBAL CONSENSUS — each island re-prices from only the elite it sees, a
#    high-variance sample on small islands.  Aggregate operator usage across ALL
#    islands into one consensus table each round (the parent has every island in
#    scope between chunks) and broadcast it to the workers via a fail-safe env-
#    pointed file, so the whole archipelago shares one low-variance economy.
ADAPTIVE_COST_FITNESS_WEIGHTED = True
ADAPTIVE_COST_FITNESS_TEMP     = 1.0    # softmax temperature in units of the elite
                                        # fitness spread (IQR); ↑ ⇒ flatter weights
ADAPTIVE_COST_MARGINAL_WEIGHT  = 0.5    # strength of the users-vs-non-users lift
                                        # correction (0 ⇒ pure frequency pricing)
ADAPTIVE_COST_ANNEAL_BAND      = True   # narrow the clamp band over a chunk
ADAPTIVE_COST_BAND_FLOOR       = 0.30   # late-chunk band width as a fraction of full
ADAPTIVE_COST_GLOBAL_CONSENSUS = True   # archipelago-wide consensus table
ADAPTIVE_COST_CONSENSUS_ENV    = "EVO13_COST_CONSENSUS_FILE"  # worker handshake var

# How often (in generations) to retarget the residual-aware seed generator at
# the *current* HoF-best's residuals and inject the new seeds into each
# island's population.  Built-in seeds are otherwise consumed only at startup,
# so on problems where no startup seed solves the target the search has to
# rediscover correction terms from scratch.  This keeps the high-quality seed
# generators in the live loop.  0 disables re-injection.
RESEED_PERIOD = 250
RESEED_INJECT_N = 5     # how many fresh seeds to splice into each island

# Master switch for population seeding.  When True (default) the search is given
# a head start: hand-crafted template individuals plus closed-form seeds
# (OLS / log-OLS / monomial / rational / residual-targeted fits) are transcribed
# straight into the initial population and re-injected periodically — these often
# solve linear / polynomial / power-law targets outright on generation 0.
# When False, every seed generator returns nothing and evolution must discover
# all structure on its own from a purely random initial population.  Set
# interactively in train_mode() via _select_use_seeds().
USE_SEEDS = True

# Plateau-driven meta-extinction: when global best loss has not improved by
# more than META_PLATEAU_REL in META_PLATEAU_GENS generations, wipe all
# islands except the global elite (`META_KEEP_FRAC`) and rebuild from fresh
# seeds (v5 + importance-biased + residual-aware).  Capped at META_MAX_FIRES
# per run so we don't thrash on intrinsically hard problems.
META_PLATEAU_GENS  = 1000
META_PLATEAU_REL   = 1e-5
META_KEEP_FRAC     = 0.05
META_MAX_FIRES     = 5

# Maximum loss an individual may have to enter the Hall of Fame.
# Expressions with billion-scale losses (abs(x)^feature blowups, etc.) would
# otherwise occupy every high-complexity HoF slot and block genuinely good
# medium-complexity expressions from entering the frontier.
# Comfortably above "mean predictor" (regression loss ~1.0) but far below
# catastrophic blow-up territory.
HOF_LOSS_CEILING = 5.0

# ── Classification best-model selection margin ───────────────────────────────
# For classification outputs the Hall-of-Fame Pareto frontier is ranked on
# ACCURACY (the metric of interest) rather than cross-entropy loss.  When two
# frontier models differ in accuracy by less than this margin they are treated
# as effectively tied and the SIMPLER (lower-complexity) one is chosen as the
# "best overall" model.  This prevents the selector from preferring a bloated,
# marginally-lower-CE model over a much simpler model with equal-or-higher
# accuracy.  0.005 == half a percentage point of accuracy.
BEST_MODEL_ACC_MARGIN = 0.005

# How often (in generations) to run the periodic algebraic simplification pass
# across the entire population and Hall of Fame.
SIMPLIFICATION_FREQ = 500

# ---- PySR-style Simulated Annealing ----
# SA acceptance: a newly generated child that is *worse* than the individual it
# would replace is still accepted with probability exp(-Δfitness / T), where
# T = SA_ALPHA * mean_population_loss.  This prevents premature convergence by
# allowing occasional uphill moves — exactly as PySR's `annealing=True` does.
# • SA_ALPHA=0.0  → pure greedy selection (SA disabled)
# • SA_ALPHA=0.1  → PySR default, mild annealing
# • SA_ALPHA=0.5  → strong annealing (noisier but harder to get stuck)
SA_ALPHA   = 0.1
SA_ENABLED = True

# Temperature-scaled constant perturbation (PySR: perturbationFactor).
# During constant Gaussian mutation the noise sigma is multiplied by
# (SA_PERTURBATION_FACTOR * T + 1).  At high T (early, bad population) constants
# explore widely; as T → 0 (good population) they are refined precisely.
SA_PERTURBATION_FACTOR = 1.0

# ---- Regression Loss Function ----
# Selects how a regression individual's raw `.loss` is computed (lower = better,
# 0 = perfect fit, ~mean-predictor = O(1)).  Both modes are variance-relative so
# the loss is unit-free and the downstream calibration (HOF_LOSS_CEILING, the
# MDL log2(loss) term, the SA temperature ∝ mean loss) is preserved.
#
#   "mse_mae"  (legacy) : (mse/var) + (mae/sqrt(var)).  Adequate on clean,
#       single-scale problems, but it has three well-known failure modes:
#         • one chaotic/discontinuous blow-up row dominates the squared term;
#         • the squared term is owned by the largest-MAGNITUDE samples, so when
#           the target spans several orders of magnitude the search fits the big
#           outputs and never bothers with the small ones (it can get STUCK
#           there — the small residuals are simply invisible to MSE);
#         • "predict the mean" is only weakly discouraged.
#
#   "robust"  (default) : the legacy two terms, made robust, PLUS two new terms.
#       It is purely ADDITIVE over the legacy loss, so on clean single-scale data
#       it behaves almost exactly like "mse_mae" (and is therefore just as stable),
#       while gaining outlier-robustness, a multi-scale term, and an anti-collapse
#       term that switch on only when they are actually needed:
#         L_mse  = 2·mean(pseudo_huber(r/s, δ))   ROBUST MSE.  Identical to
#                  mse/var for |r| ≲ δ·s (same gradient + curvature as the legacy
#                  squared term where it matters) but its tail is LINEAR, so a
#                  single chaotic / discontinuous (mod, floor, bitwise) blow-up
#                  row is counted once, not squared — robust to heavy tails.
#         L_mae  = mae / sqrt(var)                 the EXACT legacy MAE term.  Its
#                  constant near-0 gradient is what forces an EXACT fit late
#                  (vital for integer / bit / step targets) and keeps the search
#                  as well-anchored / low-variance as the legacy loss.
#         L_ms   = w·gate·mean(min(|asinh(p/c) − asinh(y/c)|, clip))   the new
#                  MULTI-SCALE term, in asinh (symlog) space.  asinh(·/c) is
#                  linear below the crossover scale c and logarithmic above it,
#                  and is defined for zeros / negatives (unlike log), so a y≈1e−3
#                  row contributes as much as a y≈1e6 row and the search can no
#                  longer ignore the small-magnitude outputs.  c = the SCALE_PCT-th
#                  percentile of the non-zero |y|.  `gate` (see below) keeps this
#                  term silent unless the target genuinely spans decades, and `w`
#                  is deliberately small so L_mse stays the dominant, smoothly
#                  convex driver of the search (a large w destabilises it).
#         L_coll = k·(1 − min(spread_p/spread_y, 1))²   graduated ANTI-COLLAPSE
#                  penalty.  Uses a robust (mean-absolute-deviation) spread ratio
#                  so an equation whose output has collapsed toward a constant /
#                  the dataset mean gets a stronger-than-averaged push out of that
#                  local optimum, smoothly (no hard step) and without misfiring on
#                  a lone outlier.
#       loss = L_mse + L_mae + L_ms + L_coll
# Set REGRESSION_LOSS_MODE = "mse_mae" to restore the exact legacy behaviour.
REGRESSION_LOSS_MODE        = "robust"   # "robust" | "mse_mae"
ROBUST_LOSS_HUBER_DELTA     = 3.0   # pseudo-Huber knee, in units of std(y); the
                                    # tail is linear beyond this (outlier robustness)
ROBUST_LOSS_MAE_WEIGHT      = 1.0   # weight of the legacy mae/sqrt(var) term (1.0
                                    # == legacy; this is the late exact-fit anchor)
ROBUST_LOSS_MULTISCALE_WEIGHT = 0.2 # weight of the gated asinh multi-scale term.
                                    # Kept small on purpose: L_mse must remain the
                                    # dominant driver of the search.  Empirically
                                    # the search degrades sharply once this rivals
                                    # L_mse (≈0.3+ on heavily skewed targets), while
                                    # 0.2 matches/beats the legacy loss everywhere
                                    # tested and still fully preserves the multi-
                                    # scale ranking (it is linear in this weight, so
                                    # the good-vs-bad gap stays the same multiple).
                                    # Raise it for a stronger pull onto the small
                                    # outputs if your target is comfortably
                                    # representable by the op set.
ROBUST_LOSS_MAE_CLIP        = 4.0   # per-row cap on |Δasinh| (asinh units ≈ log
                                    # relative error); 0 disables the cap
ROBUST_LOSS_COLLAPSE_WEIGHT = 0.5   # strength of the graduated anti-collapse push
ROBUST_LOSS_SCALE_PCT       = 25.0  # percentile of non-zero |y| used as the
                                    # absolute↔relative crossover scale c
# The multi-scale (asinh) term is only beneficial when the target genuinely spans
# orders of magnitude; on single-scale / zero-centred data it needlessly over-
# weights the near-zero rows and adds search variance.  So it is GATED by the
# data's dynamic range, measured once as log10(p90/p10) of the non-zero |y| (≈ the
# number of decades the bulk of the target spans).  The term ramps (smoothstep)
# from fully OFF below LO to fully ON at/above HI.  Empirically every single-scale
# target sits ≤ ~1.3 decades and every multi-scale one ≥ ~2.8, so [1.5, 2.5]
# cleanly separates them.  When the gate is 0 the asinh work is skipped entirely.
ROBUST_LOSS_MULTISCALE_LO   = 1.5   # decades of |y| spread below which L_ms is OFF
ROBUST_LOSS_MULTISCALE_HI   = 2.5   # decades at/above which L_ms is fully ON

# ---- Degenerate-prediction guard ----
# A model whose EXPORTED prediction is (near-)constant explains none of a varying
# target, so it must be scored like a constant predictor — never near-perfect.
# An expression can LOOK variable to the loss yet export to a constant:
#   • a "dead" branch — IF(condition-always-false, expr, 0) hard-evaluates to the
#     constant else-branch, but under DIFFERENTIABLE_BRANCHING the soft sigmoid
#     if_else leaks a tiny, VARYING slice of `expr`, so the smooth output the loss
#     sees is not constant even though the exported (hard) model is;
#   • affine amplification of a prediction whose spread is only floating-point
#     noise around a constant.
# When the export-semantics prediction's spread falls below this fraction of the
# target's spread, the loss is overridden to the median-constant-predictor loss
# and R² to 0.0 (a constant accounts for none of the variance), replacing the old
# absolute std<1e-6 → +10 penalty which left R² reading a spurious ≈1.0.
DEGENERATE_PRED_REL_TOL     = 1e-4  # |std(export_pred)| / std(y) below this ⇒ degenerate

# ---- Sobolev Training ----
# Adds a gradient-matching penalty to the regression loss.
# Target gradients dy/dX are estimated once from the training data before
# evolution (KNN local-linear regression for any input dimensionality).
# The Sobolev penalty penalises expressions whose partial derivatives diverge
# from the empirically estimated target derivatives, guiding the search toward
# symbolically interpretable structures that respect the data's local geometry.
#
# For n_features == 1: finite differences on the sorted (x, y) pairs.
# For n_features >= 2: KNN local-linear regression (compute_multivariate_target_gradients).
#
# SOBOLEV_WEIGHT : relative weight of ‖∇f - ∇̂y‖² vs value loss.
#   0.0  → disabled (pure value loss)
#   0.1  → mild nudge (recommended default)
#   0.3  → moderate (good balance)
#   1.0  → equal weight to value loss (strong gradient enforcement)
# SOBOLEV_KNN_K  : neighbourhood size for multivariate gradient estimation.
SOBOLEV_ENABLED  = False  # toggled interactively at startup
SOBOLEV_WEIGHT   = 0.3
SOBOLEV_KNN_K    = 15

# ---- Adaptive Complexity Frequency Parsimony (PySR: use_frequency) ----
# Measure how often each complexity level appears in the population and add a
# log-frequency penalty so over-crowded complexities are gently discouraged.
# This naturally maintains a spread across the complexity axis without forcing
# the user to hand-tune PARSIMONY_STRENGTH for each problem.
# • 0.0 → disabled
# • 0.03 → gentle (recommended default)
# • 0.10 → strong (pushes hard for diversity across complexity levels)
ADAPTIVE_PARSIMONY_WEIGHT  = 0.03
ADAPTIVE_PARSIMONY_ENABLED = True

# ---- Stagnation-driven complexity-pressure relaxation ----
# The common "throw everything at the problem" run can converge onto a
# suboptimal-but-good-enough solution early; the parsimony pressure then pins the
# population to that simplest plateau model, so the more-accurate (necessarily
# more-complex) structure that would dominate it never survives selection long
# enough to be discovered.  To break that lock-in WITHOUT permanently bloating
# the frontier, the per-complexity-unit parsimony cost is temporarily relaxed in
# proportion to how long an island/AFPO pool has stalled: the multiplier ramps
# from 1.0 (no stagnation → full Occam pressure) down to COMPLEXITY_RELAX_MIN at
# the extinction-patience horizon, then snaps back to 1.0 the instant a new best
# resets the stagnation counter — so the search "spends complexity" only while
# stuck and re-simplifies as soon as it finds a better basin.  The Hall of Fame
# is keyed on RAW loss, so the reported frontier is never coarsened by this; it
# only changes which parents survive during a stall.  Read at the
# parsimony_fitness choke-point via the worker-local global
# _COMPLEXITY_PRESSURE_SCALE (mirrors the Discovery-Push anneal scale).
DYNAMIC_COMPLEXITY_RELAX_ENABLED = True
COMPLEXITY_RELAX_MIN             = 0.30   # floor of the complexity-cost multiplier

# ---- Discovery Push (selection-only "extra push" reward) ----
# A small, bounded bonus SUBTRACTED from the selection fitness (lower = better)
# to give promising-but-not-yet-optimal models an extra push up the rankings —
# WITHOUT touching the raw loss / accuracy the Hall of Fame and the final
# reported model are keyed on.  It rides the exact same channel as the PySR
# frequency-parsimony adjustment and the legacy behavioural-novelty bonus
# (which it now unifies), so it only ever STEERS the search; it can never make
# the reported frontier worse than it already is.
#
# It blends three orthogonal "is this model actually going somewhere?" signals,
# each normalised to [0, 1] and weighted independently:
#
#   • SHAPE   — rank (Spearman) agreement between prediction and target.
#               Rewards models that capture the target's ORDERING / SHAPE even
#               when the magnitude is still wrong (a monotone warp that the
#               affine + constant-optimiser can still finish).  Because it is a
#               RANK statistic it sees structure the affine-fitted MSE is blind
#               to, so it pushes the search off the flat error-plateaus where
#               many distinct structures share an almost-identical loss.
#   • NOVELTY — behavioural distinctness vs the rest of the population (implicit
#               fitness sharing).  Rewards lineages whose output fingerprint is
#               rare, so structurally-different basins survive the death
#               tournament at equal raw loss and the run resists premature
#               convergence.  Supersedes the old hard-coded 0.005 / 0.015
#               novelty bonuses (the defaults below reproduce them exactly).
#   • SMOOTH  — extrapolation stability just OUTSIDE the training cloud.
#               Probes each model a fraction PUSH_SMOOTH_EXPAND beyond the data
#               (real rows pushed outward from their centroid) and rewards
#               outputs that stay bounded near the in-sample range, pushing
#               toward forms that GENERALISE rather than ones that thread the
#               sampled rows with a brittle pole / blow-up just off the edge.
#
# SHAPE and SMOOTH are intrinsic to an individual (depend only on its
# predictions and the data), so they are computed once in calculate_fitness,
# cached, and folded into parsimony_fitness via its `push` argument.  NOVELTY
# is population-relative, so it is applied in the evolution loop (where the
# population is in scope), using PUSH_NOVELTY_WEIGHT.
#
# The SHAPE + SMOOTH contribution is hard-capped at PUSH_INTRINSIC_MAX so the
# bonus can never invert a genuine loss ranking — it only breaks near-ties and
# biases exploration, the same guard rail the legacy novelty bonus relied on.
# Set PUSH_ENABLED = False (or all weights to 0.0) to disable entirely.
PUSH_ENABLED        = True
PUSH_SHAPE_WEIGHT   = 0.020   # max fitness bonus from perfect rank-agreement
PUSH_SMOOTH_WEIGHT  = 0.010   # max fitness bonus from clean extrapolation
PUSH_NOVELTY_WEIGHT = 0.005   # per-population behavioural-uniqueness bonus
                              # (archive-novelty bonus is 3× this); 0.005 keeps
                              # the historical tuned magnitude exactly.
PUSH_INTRINSIC_MAX  = 0.025   # hard cap on the summed SHAPE + SMOOTH bonus
PUSH_SHAPE_MAX_ROWS = 2048    # subsample cap for the O(M·logM) rank computation
PUSH_SMOOTH_PROBE_K = 32      # held-out probe rows for the smoothness signal
PUSH_SMOOTH_EXPAND  = 0.25    # fraction beyond the data the probes extrapolate

# ---- Discovery Push refinements (4th signal + annealing + graded novelty) ----
# • TAILS — a 4th orthogonal intrinsic signal: rank (Spearman) agreement on just
#   the EXTREME rows (top + bottom PUSH_TAILS_FRAC of the target).  Full-sample
#   SHAPE is dominated by the dense bulk, so a model that tracks the middle but
#   saturates / flips on the extremes (a pole, a clipped exp, a missed tail)
#   still scores high on SHAPE; TAILS rewards getting the *informative* extremes
#   ordered right, which is exactly where promising structure is usually still
#   incomplete.  Shares the PUSH_INTRINSIC_MAX cap with SHAPE + SMOOTH, so it
#   can never invert a genuine loss ranking.  Weight 0 ⇒ signal off (legacy).
# • ANNEALING — the push is exploration pressure; it should fade as a search
#   epoch matures so it never perturbs the near-converged frontier.  The whole
#   push (intrinsic + novelty) is scaled by a per-chunk cosine that rides from
#   1.0 down to PUSH_ANNEAL_FLOOR, mirroring the SA temperature schedule already
#   used here (which is likewise per-chunk — the run has no global gen budget).
#   ENABLED=False pins the scale at 1.0 (legacy fixed-magnitude push).
# • GRADED NOVELTY — the legacy novelty bonus is binary (unique ⇒ full bonus,
#   else 0).  Grade it by behavioural local DENSITY instead: a child sharing its
#   fingerprint with many peers gets little, a behaviourally rare one gets the
#   full bonus, smoothly — proper implicit fitness sharing.  GRADED=False
#   restores the binary peer-match bonus exactly.
PUSH_TAILS_WEIGHT   = 0.008   # max fitness bonus from perfect extreme-row ordering
PUSH_TAILS_FRAC     = 0.2     # top+bottom fraction of the target defining "extremes"
PUSH_ANNEAL_ENABLED = True
PUSH_ANNEAL_FLOOR   = 0.15    # push scale floor at the end of a chunk (0 ⇒ fully off late)
PUSH_NOVELTY_GRADED = True    # graded density novelty vs the legacy binary bonus

# ---- Discovery Push: magnitude-gap gating of the SHAPE/TAILS reward ----
# The shape/tails push exists to RESCUE models with the right ordering but a
# not-yet-realised magnitude — the prime "finetune me into place" candidates.
# Once the affine + constants have actually landed the magnitude the model wins
# on raw loss and no longer needs the nudge.  With this enabled the SHAPE and
# TAILS components are scaled per-individual by how much of the target magnitude
# is still UNexplained AFTER the affine finetune — (1 − R²), clamped to [0, 1] —
# so the bounded push concentrates on structurally-promising forms whose
# magnitude is still wrong (e.g. a monotone NON-linear warp the linear affine
# cannot finish: R² low, ρ≈1 ⇒ near-full push) and recedes for forms the affine
# already nailed (R²→1 ⇒ push→0).  This is the literal "focus on shape, THEN
# finetune the magnitude" curriculum expressed per-individual, complementing the
# whole-search PUSH_ANNEAL_* time fade.  SMOOTH is a generalisation signal, not a
# magnitude one, so it is deliberately left ungated.  Default False ⇒ the legacy
# fixed-size bonus (so the existing capped-bonus contract is bit-for-bit intact).
PUSH_SHAPE_MAG_GATE = False

# ---- Evolution model ----
# "island"          = Island Model (multi-process)
# "afpo"            = Age-Fitness Pareto Optimisation (default, single-process)
# "island_afpo"     = Islanded AFPOs: N islands each running their own AFPO (parallel)
# "age_group_islands" = Age Group Islands: tiered AFPO where best individuals
#                      graduate from younger to older age-group island pools
EVOLUTION_MODEL = "afpo"

# Number of islands for Island and Islanded-AFPO models (set interactively)
NUM_ISLANDS_GLOBAL = 4

# Age Group Islands settings (set interactively)
AGE_GROUP_N_GROUPS          = 3    # number of age tiers
AGE_GROUP_ISLANDS_PER_GROUP = 2    # AFPO islands per tier
AGE_GROUP_GRAD_FREQ         = 100  # every N generations, graduate best from each tier

# Configurable AFPO stages for "afpo" and "island_afpo" models (set interactively)
AFPO_N_STAGES        = 1    # pipeline stages (1 = classic single-stage behaviour)
AFPO_STAGE_GRAD_FREQ = 100  # gens between stage-graduation events (when AFPO_N_STAGES > 1)

# ---- Down-Sampled Lexicase ----
# Fraction of the training set used for DS-Lexicase each generation.
# 0.0 = disabled (use fixed n_cases=20 as before).
# 0.05–0.10 recommended when enabled.
DS_LEXICASE_FRAC = 0.0

# ---- Automatically Defined Functions (ADF) ----
# Enabled via interactive prompt after operator selection.
ADF_ENABLED            = False
ADF_MODULARITY_THRESH  = 0.30   # minimum Q score to trigger extraction
ADF_FITNESS_THRESH     = 0.50   # maximum normalised fitness percentile (lower = better)
ADF_MAX_LIBRARY        = 8      # cap on how many ADFs can be accumulated
ADF_EXTRACT_FREQ       = 500    # check for new ADFs every N generations
ADF_RETIRE_PATIENCE    = 3      # consecutive zero-use cycles before an ADF is retired
_ADF_REGISTRY          = []     # list of serialisable ADF dicts (shared state)
_ADF_ZERO_USE_COUNT    = {}     # name → consecutive zero-usage extraction cycles

# ---- Arithmetic Interval mode ----
# Runs Unsafe ops but periodically evaluates every individual against the
# FULL training input range.  Any individual whose expression yields NaN or
# Inf on any training row is immediately penalised / discarded.
# Unlike naive symbolic interval arithmetic this handles the actual data
# distribution (including all interaction patterns between variables).
INTERVAL_MODE       = False   # set interactively via select_ops_safety()
INTERVAL_CHECK_FREQ = 100     # how often (in generations) to run stability scan

# ---- Logit Saturation Penalty (Interval Mode) ----
# When INTERVAL_MODE is enabled for classification outputs, penalise individuals
# whose raw logit outputs are extremely saturated (|logit| >> threshold).
# Saturated logits map to probabilities ≈ 0 or ≈ 1 through sigmoid/softmax,
# causing:  (a) overconfident predictions that don't generalise,
#           (b) vanishing gradients for boosting pseudo-residuals,
#           (c) numerical issues in BCE/softmax CE computation.
# The penalty is: WEIGHT * mean(max(0, |logit| - THRESHOLD)²)
# This keeps logits in a numerically healthy range without restricting the
# sign or rough magnitude of the output.
# Also available for regression to discourage extreme prediction magnitudes.
LOGIT_SATURATION_THRESHOLD  = 12.0   # |logit| above this is penalised
LOGIT_SATURATION_WEIGHT     = 0.05   # penalty coefficient
LOGIT_SATURATION_REG_ENABLE = False  # also apply to regression (extreme pred penalty)

# ---- Class-Imbalance Handling ----
# With unbalanced multiclass / binary classification targets, the un-weighted
# softmax-CE / BCE loss is dominated by the majority class.  Evolution then
# converges to "predict the majority class" because rare-class samples only
# contribute a tiny fraction of the mean loss — exactly the failure mode the
# user reported on the orbital-temperature dataset (Habitable rows are ~7 %).
#
# When CLASS_WEIGHT_MODE is non-'none', each sample contributes to the loss
# weighted by 1/freq(true_class), normalised so the mean weight stays ≈1.
# This gives every class equal voice in the gradient-search signal, so rare
# classes get developed instead of being absorbed into the majority prior.
#
# Modes:
#   'none'           → no re-weighting (legacy behaviour)
#   'balanced'       → w_c = N / (K · count_c) (sklearn-style; strongest)
#   'sqrt_balanced'  → w_c = sqrt(N / (K · count_c)) (gentler; recommended
#                      default — strong enough to develop rare classes
#                      without making rare-class noise dominate)
#
# Applied to:
#   • Softmax-CE loss for multi-class one-hot groups (calculate_fitness)
#   • BCE loss for binary classification outputs (calculate_fitness)
#   • optimize_constants objective for both above
#   • epsilon-lexicase per-case errors (so rare-class cases survive case-by-case
#     filtering in proportion to their importance, not their raw count)
#   • Gradient-boosting Hessian weights (so the regression-on-residuals stage
#     upweights rare-class rows when fitting pseudo-residuals)
#
# Accuracy/argmax metrics remain unweighted so they stay comparable.
CLASS_WEIGHT_MODE     = 'sqrt_balanced'  # 'none' | 'balanced' | 'sqrt_balanced'
CLASS_WEIGHT_ENABLED  = True             # toggled interactively at startup

# ---- Per-example difficulty weighting (hard-example mining / boosting) ----
# OPTIONAL, OFF BY DEFAULT (toggled interactively at startup).  When enabled,
# every training example is given a stable ID (its row index) and a "difficulty
# weight" that starts at 1.0.  Once per generation the current champion (the
# lowest TRUE-loss individual) is evaluated on the full training set, and every
# example it mis-predicts has its weight multiplicatively increased (capped).
# Those weights then reshape the per-example contribution to the SELECTION
# objective, so the search spends progressively more effort on the handful of
# examples it keeps getting wrong.  As the easy majority is learned their
# weights stop growing while the persistent outliers keep climbing, so the
# population is pulled toward fixing those last hard cases — exactly the
# AdaBoost-style focusing dynamic.
#
# This is selection-only, mirroring parsimony / const-cost / class weighting:
#   • `.fitness` (parent selection, AFPO Pareto trim, SA acceptance) and the
#     epsilon-lexicase per-case errors see the re-weighted objective, so the
#     SEARCH is steered toward the hard examples.
#   • `.loss` / `.accuracy` (the Hall-of-Fame key, the protected champion, the
#     reported metrics and the validation score) stay on the TRUE, unweighted
#     objective, so the frontier and the model you finally get are reported
#     honestly.
#
# WHY IT IS OPTIONAL: chasing the examples a model can't fit is exactly what you
# want when those examples are genuine but under-represented structure — and
# exactly what you DON'T want when they are label noise.  Up-weighting noisy
# rows makes evolution contort the expression to memorise them, i.e. it
# OVERFITS.  Leave it off unless you know your hardest rows are signal.
#
# A "failure" is: wrong class (classification) or a residual larger than
# INSTANCE_REWEIGHT_REG_TOL × std(y) (regression — a scale-free "not close
# enough").  Because stable per-example IDs are required, enabling this forces
# full-dataset evaluation (mini-batching is disabled for the run).
INSTANCE_REWEIGHT_ENABLED      = False   # toggled interactively at startup
INSTANCE_REWEIGHT_INCREMENT    = 0.15    # weight *= (1 + this) per failed generation
INSTANCE_REWEIGHT_MAX          = 8.0     # per-example weight ceiling (anti-runaway)
INSTANCE_REWEIGHT_REG_TOL      = 0.25    # regression: |resid| > tol*std(y) counts as a miss
INSTANCE_REWEIGHT_UPDATE_EVERY = 1       # re-score / re-weight every N generations

# ---- Competitive Co-Evolution (Hillis Predator–Prey, adapted for SR) ----
# Hillis (1990) co-evolved sorting networks (hosts) against an adversarial
# population of test cases (parasites).  Adapted to symbolic regression: each
# *parasite* encodes a fixed-size subset of the training rows ("fitness cases"),
# and the parasite population evolves to surface the rows on which the current
# best equations perform WORST.  The hosts (the equations, evolved by whichever
# EVOLUTION_MODEL is chosen) are then trained on that adversarial subset each
# chunk instead of on a random mini-batch, so the search is continually pushed
# at its own weak points in an arms race.
#
# The size of a parasite's fitness-case subset is the co-evolution analogue of
# the mini-batch size: it is how many rows the hosts see each generation.
# Disengagement (parasites becoming so hard the hosts get no usable gradient
# and the arms race stalls) is countered with Cartlidge & Bullock's (2004)
# *reduced virulence* λ: a parasite's reward peaks at host-failure level λ
# rather than at 1.0, keeping both populations engaged.  Toggled interactively
# at startup (default OFF).
#
# Four failure modes of the naive predator–prey loop are guarded against here,
# all on by default (set the corresponding knob to disable):
#   1. NOISE-LATCHING — on a near-perfect model the only "hard" rows left are the
#      irreducible-noise ones, so the predators collapse the whole batch onto
#      label noise and wreck a good fit.  Countered by (a) a robust, *absolute*
#      row-hardness (scaled by the target spread and squashed into [0,1), so one
#      wild outlier can no longer define the scale and a good model yields a
#      genuinely low signal) and (b) a persistence-based NOISE GUARD that
#      discounts rows which stay hard *despite* being trained on repeatedly
#      (≈ unlearnable / mislabelled).
#   2. SUBSET COLLAPSE — the whole parasite population converging on one cluster
#      of rows, so the hosts only ever see `subset` examples.  Countered by
#      Rosin & Belew (1995)-style competitive FITNESS SHARING (reward parasites
#      for covering hard rows the rest of the pack does not).
#   3. OFF-DISTRIBUTION DRIFT — a 100%-adversarial batch lets the hosts forget
#      the bulk data.  Countered by mixing a uniform-random ANCHOR fraction into
#      every batch (also guarantees the whole dataset is covered over time).
#   4. CYCLING / CATASTROPHIC FORGETTING — the Red-Queen failure that bites hard
#      on many-variable targets: the predators swing the batch onto a narrow
#      region that exercises only *some* inputs, the hosts overfit it and prune
#      the variables that region doesn't need, then the predators swing back and
#      the hosts have to RELEARN the dropped variable — the search oscillates
#      instead of converging.  The parasites act on rows, not variables, but a
#      dropped variable has a model-agnostic signature: the rows that depend on it
#      REGRESS from a fit the hosts had already achieved.  Countered by (a)
#      progress TRACKING — the global host loss, its trend, a per-row best-ever
#      fit and the mean regression ("forgetting") — feeding (b) a STABILISER that,
#      while the hosts are forgetting, WIDENS the uniform anchor (more breadth, so
#      every variable stays represented) and damps the predators' virulence,
#      relaxing back to the configured aggression once the loss falls cleanly.
#      (Closed-loop simulation found breadth — not re-injecting the specific
#      dropped rows, which just duplicates what the predators already chase — is
#      the lever that actually fixes the forgetting.)
COEVOLUTION_ENABLED = False   # master switch (asked just before batch size)
COEVO_CASE_SUBSET   = 64      # rows per parasite — the mini-batch-size analogue
COEVO_POP_SIZE      = 32      # number of parasites in the predator population
COEVO_MUT_RATE      = 0.30    # fraction of a parasite's rows resampled per mutation
COEVO_VIRULENCE     = 0.75    # reduced-virulence λ ∈ (0,1]  (1.0 = full virulence)
COEVO_ANCHOR_FRAC   = 0.25    # fraction of each batch drawn uniformly at random
                              # ("anchor": keeps the hosts on the bulk distribution
                              #  and guarantees whole-dataset coverage; 0 = legacy
                              #  pure-adversarial behaviour)
COEVO_FITNESS_SHARING = True  # reward parasites for covering rows the rest of the
                              # population does not (anti subset-collapse)
COEVO_NOISE_GUARD   = True    # discount rows that stay hard despite repeated
                              # training (anti noise-latching)
COEVO_HARDNESS_EMA  = 0.20    # EMA rate for the per-row hardness the guard tracks
COEVO_GUARD_PATIENCE = 5.0    # ~how many times a row must be trained on before the
                              # guard treats persistent hardness as irreducible
COEVO_GUARD_STRENGTH = 0.90   # max fraction a fully-resistant row's hardness is cut
COEVO_GUARD_FLOOR   = 0.05    # never discount a row's hardness below this factor
# ---- Progress tracking + arms-race stabilisation (anti cycling/forgetting) ----
# These counter failure mode 4 above (the one that bites on 10+-input targets).
# Every chunk the hosts' GLOBAL loss, its short-term trend, and a per-row
# best-ever fit are tracked; from those a FORGETTING signal (how much of the
# signal the hosts have dropped vs their best — the dropped-variable signature)
# and a smoothed INSTABILITY ∈ [0,1] are derived.  While instability is high the
# stabiliser widens the uniform ANCHOR — i.e. injects more breadth — and damps the
# predators' virulence, which is what stops the search oscillating/forgetting on
# many-variable targets (closed-loop simulation: breadth is the lever that keeps
# every variable represented; a too-narrow adversarial batch is what drops them).
# The tracking itself is always on (it's pure observation, surfaced in the
# per-generation log); only the batch-shaping ACTION is gated by COEVO_STABILIZE.
COEVO_STABILIZE       = True  # adaptively widen the anchor + damp predators while
                              # the hosts are forgetting (False ⇒ exact legacy arms race)
COEVO_ANCHOR_BOOST    = 0.30  # extra anchor fraction added at full instability
COEVO_VIRULENCE_DAMP  = 0.40  # max fraction the effective virulence λ is cut at full
                              # instability (calmer, less-aggressive predators)
COEVO_ADV_FLOOR       = 0.30  # the core arms race always keeps ≥ this batch fraction
                              # (so the boosted anchor can never swamp the predators)
COEVO_BEST_DOWN       = 0.50  # per-row best-ever hardness: fast snap-DOWN rate
COEVO_BEST_UP         = 0.02  # ...and slow drift-UP rate (a row that turns
                              #  permanently hard is gradually forgiven, so it stops
                              #  reading as "forgotten" forever — keeps noise out)
COEVO_INSTAB_RATE     = 0.25  # EMA smoothing rate for the instability signal
COEVO_INSTAB_SENS     = 0.50  # relative loss-rise that maps to full instability
COEVO_FORGET_SENS     = 0.12  # mean per-row regression that maps to full instability
                              # (the plateau-robust term: fires even when the loss is
                              #  stuck high but variables are taking turns dropping)
COEVO_LOSS_FAST       = 0.40  # fast global-loss EMA rate  ┐ trend = fast − slow
COEVO_LOSS_SLOW       = 0.10  # slow global-loss EMA rate  ┘ (>0 ⇒ regressing)
COEVO_LOSS_FLOOR      = 0.02  # denominator floor for the *relative* loss-rise term of
                              # instability.  On a near-perfect model the slow loss is
                              # ≈0, so a float-scale uptick would read as a huge
                              # RELATIVE rise and falsely spike instability to ~1 (and
                              # needlessly widen the anchor / damp the predators).
                              # Flooring the denominator treats sub-`floor` loss as
                              # "already solved" — only a rise off a meaningful loss
                              # counts.  (0 ⇒ legacy behaviour, still divide-safe.)
_COEVO_RUNTIME      = None    # lazily-built _PredatorPreyCoevolution instance

# ---- Bayesian CGP Settings ----
# Bayesian optimisation uses a Gaussian Process surrogate to model the
# fitness landscape over CGP genotype space, and Expected Improvement (EI)
# to pick which candidate mutations to actually evaluate.  This is much
# more sample-efficient than pure evolution but more expensive per iteration.
BAYESIAN_INITIAL_SAMPLES = 100    # random individuals evaluated before BO starts
BAYESIAN_BATCH_SIZE      = 30     # candidates evaluated per BO iteration
                                  # (20→30 to give the per-iter BO throughput
                                  # a closer match to a single evolutionary
                                  # island's per-generation eval count — BO
                                  # is single-process so it has to make each
                                  # iter count)
BAYESIAN_N_CANDIDATES    = 200    # mutation candidates generated per iteration
BAYESIAN_GP_REFIT_FREQ   = 5      # refit GP every N iterations
BAYESIAN_EXPLORATION     = 0.05   # exploration–exploitation trade-off (xi for EI)
                                  # Bumped 0.01 → 0.05 because at 0.01 EI was
                                  # essentially greedy on the GP's best-of-buffer
                                  # estimate; the surrogate is uncertain over
                                  # most of the encoding manifold for CGP, so
                                  # we need more xi for the acquisition to ever
                                  # pick candidates that aren't structurally
                                  # adjacent to the existing buffer best.
BAYESIAN_MAX_GP_POINTS   = 500    # cap on GP training set (oldest evicted first)
BAYESIAN_CONST_OPT_FREQ  = 10     # run light const-opt on HoF every N iterations
BAYESIAN_VARIANT         = "regular" # bayesian variant

# ── Interplay Escape Oracle ──────────────────────────────────────────
# The Bayesian surrogate is excellent at refining variants of a template
# that already scores well — and that's exactly its failure mode on
# multi-interplay targets like
#     (A·B)·log(B) − 10·A / (√(A·B) + (B−A) − (B/A) − (A/√B))
# where the answer requires composing ~6 distinct (op_cat, feat_pair)
# interplays.  Once EI locks onto one good basin the GP only ever sees
# variants of that basin, and the search converges to whichever single
# template fits best instead of building the compound expression.
#
# The Interplay Escape Oracle gives the Bayesian a way to act as the
# "intelligent evolution master" the underlying engines need:
#   1. It records the (op_category, feature_ancestor_set) atoms that
#      appear in every evaluated tree, and the full structural signature
#      of each candidate.
#   2. When recent buffer additions collapse onto a single dominant
#      signature (low entropy / one signature claiming >threshold of
#      the buffer) for several consecutive iterations, the oracle
#      flags "escape mode" for ESCAPE_DURATION iterations.
#   3. During escape mode, the outer BO loop:
#        - allocates ESCAPE_SEED_FRAC of its candidate budget to seeds
#          synthesised against MISSING atoms (interplays never seen),
#        - uses a Boltzmann (softmax-over-loss) Stage-2 selection at
#          temperature ESCAPE_TEMPER_T so screen-losers occasionally
#          get full evaluation — the "be less afraid to try worse
#          formulas" mechanism,
#        - asks the GP-Hedge portfolio to boost its exploration arms
#          (UCB / PE / TS / KG) so the surrogate's acquisition stops
#          ranking everything by the basin's local gradient.
# Set BAYESIAN_ESCAPE_ENABLED = False to disable the oracle entirely.
BAYESIAN_ESCAPE_ENABLED       = True   # master switch for the oracle
BAYESIAN_ESCAPE_PATIENCE      = 6      # consecutive low-entropy iters before escape fires
BAYESIAN_ESCAPE_ENTROPY_FRAC  = 0.55   # H / log(unique_signatures) below this counts as inbred
BAYESIAN_ESCAPE_DOMINANT_FRAC = 0.50   # one signature claiming >this of buffer also counts
BAYESIAN_ESCAPE_DURATION      = 4      # iters spent in escape mode per trigger
BAYESIAN_ESCAPE_SEED_FRAC     = 0.25   # candidate-budget share devoted to escape seeds
BAYESIAN_ESCAPE_TEMPER_T      = 1.5    # Stage-2 softmax temperature (× loss range)
BAYESIAN_ESCAPE_RECENT_WINDOW = 30     # iterations tracked in the recent-signature window

QUALITY_DIVERSITY_ENABLED = False # QD algorithms



# --- IMPORTS FOR SIMPLIFICATION ---
try:
    import sympy
    from sympy.printing.numpy import NumPyPrinter
except ImportError:
    print("Warning: 'sympy' not found. Equations will not be simplified.")
    sympy = None

warnings.filterwarnings('ignore')
np.seterr(all='ignore')

# ==========================================
# IMPROVEMENT 1: ACTIVE-GRAPH FITNESS CACHE
# ==========================================
# Caches fitness results keyed by the active-graph fingerprint so that
# genotypically converging populations (where many individuals share the same
# effective computation) skip redundant evaluate() calls entirely.
# The fingerprint ignores inactive nodes (junk DNA), focusing on what the
# expression actually computes.
#
# Thread / process safety: each worker process gets its own cache instance
# (Python multiprocessing uses fork or spawn; the global is not shared).
# Cache is cleared on extinction to prevent stale entries from poisoning
# post-extinction diversity.

class _FitnessCache:
    """FIFO cache keyed by (active-graph fingerprint, target-hash)
    → Individual attributes.

    Eviction is by insertion order (oldest 20 % drop on overflow), not LRU
    — recent reads do not refresh entries.  Renamed from "LRU-like" because
    the previous docstring was misleading.
    """

    def __init__(self, maxsize: int = 8000):
        self._cache: dict = {}
        self._order: list = []     # insertion order for eviction
        self._maxsize = maxsize
        self.hits = 0
        self.misses = 0
        # Guard the eviction loop + (_cache, _order) pair against torn updates
        # when re-scoring HoFs is parallelised across outputs with threads.
        # Dict get and single put are atomic in CPython, but the size-check
        # → evict → insert sequence is not — under contention the _order list
        # and _cache dict could disagree on which keys are tracked, causing
        # KeyErrors on later eviction.
        self._lock = threading.Lock()

    def _fingerprint(self, tree) -> tuple:
        """
        Canonical tuple representation of the *active* CGP graph.
        Inactive nodes are ignored entirely.  Const values are rounded to
        4 significant figures so near-identical constants collapse together.
        """
        tree.update_active_nodes()
        parts = []
        for idx in sorted(tree.active_nodes):
            if idx < tree.n_features:
                parts.append(('F', idx))
            else:
                node = tree.nodes[idx - tree.n_features]
                if node.op == 'const':
                    # round to 4 sig-figs to tolerate floating-point noise
                    v = float(f"{node.const_val:.4g}")
                    parts.append(('C', v))
                elif node.op in CGPEquation.OPS_TERNARY_SET:
                    parts.append((node.op, node.in1, node.in2, node.in3))
                else:
                    parts.append((node.op, node.in1, node.in2))
        parts.append(('O', tree.out_idx))
        return tuple(parts)

    @staticmethod
    def _target_sig(y_target) -> tuple:
        """Stable digest of the full target array.

        The previous fingerprint was ``(y[0], y[-1], len(y))`` which collided
        between *every* gradient-boosting stage's residuals (same length,
        same endpoints) and silently returned the wrong cached fitness.
        We now hash the entire byte buffer so any value change invalidates
        the cache; blake2b is fast enough for the array sizes involved.
        """
        arr = np.ascontiguousarray(y_target)
        return (
            arr.shape,
            str(arr.dtype),
            hashlib.blake2b(arr.tobytes(), digest_size=16).digest(),
        )

    def get(self, tree, y_target) -> dict | None:
        """Return cached result dict or None on miss."""
        fp = (self._fingerprint(tree), self._target_sig(y_target))

        if fp in self._cache:
            self.hits += 1
            return self._cache[fp]
        self.misses += 1
        return None

    def put(self, tree, y_target, result: dict):
        """Store result dict for this tree's fingerprint AND target."""
        fp = (self._fingerprint(tree), self._target_sig(y_target))

        with self._lock:
            if fp in self._cache:
                self._cache[fp] = result
                return
            if len(self._cache) >= self._maxsize:
                # FIFO eviction: drop oldest 20 % by insertion order.
                evict_n = max(1, self._maxsize // 5)
                for old_fp in self._order[:evict_n]:
                    self._cache.pop(old_fp, None)
                self._order = self._order[evict_n:]
            self._cache[fp] = result
            self._order.append(fp)

    def clear(self):
        with self._lock:
            self._cache.clear()
            self._order.clear()

    def stats_str(self) -> str:
        total = self.hits + self.misses
        rate = self.hits / max(total, 1)
        return f"cache hits={self.hits}/{total} ({rate:.1%}), size={len(self._cache)}"


# Process-local singleton
_FITNESS_CACHE = _FitnessCache(maxsize=8000)

# Initialization-phase flag: when True, modularity is skipped and
# evaluation can use a subsample.  Set True during population init,
# cleared before evolution begins.  This makes large-dataset startup
# dramatically faster.
_INIT_PHASE = False
_INIT_SUBSAMPLE_CAP = 5000   # max rows during init evaluation

# ============================================================
# Per-feature priors (importance weights) shared across the
# search.  When set, ``random_cgp`` and the rewire/decompose
# branches of ``mutate`` bias their feature-pick toward
# features that actually correlate with the target.  Critical
# for problems with > 5-7 input variables, where uniform
# feature selection drowns the relevant inputs in junk.
#
# The dict is keyed by output index because feature importance
# can differ across outputs.  A None value means "fall back to
# uniform"; the helpers below handle that case transparently.
# ============================================================
FEATURE_PRIORS = None        # numpy array of length n_features, or None
FEATURE_PRIOR_BIAS = 0.65    # mixing weight: 1.0 = pure prior, 0.0 = uniform


def set_feature_priors(weights):
    """Set the global per-feature importance prior used during search.

    ``weights`` should be a numpy array (length n_features) summing to 1.
    Pass ``None`` to disable (fall back to uniform feature selection).
    """
    global FEATURE_PRIORS
    if weights is None:
        FEATURE_PRIORS = None
        return
    arr = np.asarray(weights, dtype=np.float64)
    if not np.isfinite(arr).all() or arr.size == 0:
        FEATURE_PRIORS = None
        return
    s = float(arr.sum())
    if s <= 0:
        FEATURE_PRIORS = None
        return
    FEATURE_PRIORS = arr / s


def _pick_feature_idx(n_features, max_index=None, bias=None):
    """Pick a feature index, optionally biased by ``FEATURE_PRIORS``.

    ``max_index`` caps the upper bound (exclusive); when None, defaults to
    ``n_features``.  When ``FEATURE_PRIORS`` is set, mixes prior * uniform
    according to ``bias`` (defaults to ``FEATURE_PRIOR_BIAS``).  Falls
    back to uniform when the prior is missing or has wrong shape.
    """
    if max_index is None:
        max_index = n_features
    max_index = max(1, int(max_index))
    if max_index >= n_features:
        max_index = n_features

    if FEATURE_PRIORS is None or len(FEATURE_PRIORS) != n_features or max_index <= 1:
        return random.randint(0, max_index - 1)

    b = FEATURE_PRIOR_BIAS if bias is None else float(bias)
    b = max(0.0, min(1.0, b))
    # When max_index < n_features (e.g. early CGP slots that can't
    # reference later features), restrict the prior to the feasible head
    # and renormalise on the fly.
    head = FEATURE_PRIORS[:max_index].astype(np.float64)
    s = float(head.sum())
    if s <= 0:
        return random.randint(0, max_index - 1)
    head = head / s
    uniform = np.full(max_index, 1.0 / max_index, dtype=np.float64)
    mixed = b * head + (1.0 - b) * uniform
    mixed = mixed / float(mixed.sum())
    try:
        return int(np.random.choice(max_index, p=mixed))
    except Exception:
        return random.randint(0, max_index - 1)


# ==========================================
# IMPROVEMENT 2: ADAPTIVE REPRODUCTIVE OPERATOR WEIGHTS
# ==========================================
# Tracks which reproductive actions (mutate, crossover, grow, prune, …) most
# frequently produce children that are accepted into the population (i.e. that
# beat the death-tournament victim).  Uses an exponential moving average of
# per-operator success rates (SHADE-inspired) to dynamically re-weight
# operator selection each generation.
#
# Exploration is preserved via UCB-style mixing: w_i = base_i × (0.4 + 0.6 × sr_i)
# so no operator can ever be fully suppressed (minimum 40% of its base weight).

class AdaptiveMutationTracker:
    """
    Per-island tracker for reproductive operator success rates.

    Usage:
        tracker = AdaptiveMutationTracker(repro_ops, base_weights)
        action  = tracker.choose()
        ...
        child_accepted = (delta_fit < 0)
        tracker.record(action, child_accepted)
        # Every ~50 generations:
        adapted_weights = tracker.get_weights()
    """

    def __init__(self, ops: list, base_weights: list, alpha: float = 0.08):
        assert len(ops) == len(base_weights)
        self.ops          = ops
        self.base_weights = list(base_weights)
        self.alpha        = alpha                        # EMA decay
        # Initialise all operators at neutral (50% success)
        self.sr: dict     = {op: 0.5 for op in ops}
        self.counts: dict = {op: 0   for op in ops}

    def record(self, op: str, success: bool):
        """Update EMA success rate for op."""
        if op not in self.sr:
            return
        self.counts[op] += 1
        self.sr[op] = (1.0 - self.alpha) * self.sr[op] + self.alpha * (1.0 if success else 0.0)

    def choose(self) -> str:
        """Sample an operator using current adapted weights."""
        w = self.get_weights()
        return random.choices(self.ops, weights=w, k=1)[0]

    def get_weights(self) -> list:
        """
        Return weight list for random.choices().
        w_i = base_i × (0.4 + 0.6 × sr_i)   — always ≥ 40% of base.
        """
        return [bw * (0.4 + 0.6 * self.sr[op])
                for bw, op in zip(self.base_weights, self.ops)]

    def summary(self) -> str:
        lines = ["  Operator success rates:"]
        for op in self.ops:
            lines.append(f"    {op:<14} sr={self.sr[op]:.3f}  n={self.counts[op]}")
        return "\n".join(lines)


# ==========================================
# IMPROVEMENT 3: OPERATOR AFFINITY SCORING
# ==========================================
# Tracks which primitive operators appear in HoF expressions and biases
# OPS_ALL sampling toward operators with proven track records on THIS problem.
# Called periodically from the main loop; results are passed into mutation.

def compute_hof_operator_affinity(hofs, smoothing: float = 0.5) -> dict:
    """
    Count how often each operator appears in active nodes across all HoF
    entries and return a normalised affinity dict: op → weight ∈ (0, 1].

    Smoothing prevents any operator from being zeroed out.  All operators
    not seen in HoF entries receive weight = smoothing / (smoothing + max_count).
    """
    counts: dict = {}
    total_inds = 0
    for hof in hofs:
        for ind in hof.best_by_complexity.values():
            if ind is None:
                continue
            total_inds += 1
            ind.tree.update_active_nodes()
            for idx in ind.tree.active_nodes:
                if idx >= ind.tree.n_features:
                    op = ind.tree.nodes[idx - ind.tree.n_features].op
                    if op != 'const':
                        counts[op] = counts.get(op, 0) + 1

    if not counts:
        return {}

    max_c = max(counts.values())
    affinity = {}
    for op in CGPEquation.OPS_ALL:
        c = counts.get(op, 0)
        affinity[op] = (c + smoothing) / (max_c + smoothing)
    return affinity


def affinity_biased_op_choice(affinity: dict, ops: list | None = None) -> str:
    """Sample from ops (default: OPS_ALL) weighted by HoF affinity.

    A small exploration floor (0.10) is enforced on every operator so that
    once the HoF stabilizes on a few primitives, exploration of the rest
    doesn't collapse to ~0 probability.  Without the floor a HoF using only
    `+ * /` would zero-pressure `sin/exp/log` discovery; with the floor each
    such op still has at least a 10% relative chance of being sampled.
    """
    if ops is None:
        ops = CGPEquation.OPS_ALL
    if not affinity:
        return random.choice(ops)
    weights = [max(affinity.get(op, 0.3), 0.10) for op in ops]
    return random.choices(ops, weights=weights, k=1)[0]


# ==========================================
# DATA-DRIVEN OPERATOR PRIOR (de-novo discovery aid)
# ==========================================
# `compute_hof_operator_affinity` learns which operators *worked* — but it
# needs a populated Hall of Fame to say anything, so for the first chunks of a
# fresh run it is silent.  The data-driven prior below is its complement: it
# guesses which operators *should* work straight from (X, y), before any
# evolution has happened.  This is what keeps AFPO productive when it cannot
# lean on seed templates — seeds disabled, a bitwise-only op set, or a dataset
# whose shape matches no hand-crafted seed.  evolve_afpo computes the prior once
# from its (X, y) and threads it explicitly into the random_cgp immigrant/pad
# calls and (via _blend_op_affinity) into mutation's operator choice, so
# genuinely novel structure is steered toward the function families the data
# actually exhibits instead of a hard-coded arithmetic backbone.


def _blend_op_affinity(data_prior, hof_affinity):
    """Combine the data-driven prior with the HoF-learned affinity by taking
    the element-wise max.  Semantics: an operator is favoured if *either* the
    data suggests it (prior) *or* the HoF has found it useful (affinity).  This
    keeps data-relevant operators alive during exploration even before the HoF
    discovers them, while never suppressing an operator the HoF already relies
    on.  Either argument may be empty/None."""
    if not data_prior:
        return dict(hof_affinity) if hof_affinity else {}
    if not hof_affinity:
        return dict(data_prior)
    out = {}
    for op in set(data_prior) | set(hof_affinity):
        out[op] = max(float(data_prior.get(op, 0.0)),
                      float(hof_affinity.get(op, 0.0)))
    return out


def compute_data_operator_prior(X, y, type_code=5, max_rows=512):
    """Cheap, one-shot operator prior derived directly from the data.

    Returns a dict mapping every operator in ``CGPEquation.OPS_ALL`` to a
    weight in (0, 1], normalised so the strongest-signal family ≈ 1.0 and the
    baseline floors at 0.3 (matching ``affinity_biased_op_choice``'s default
    for unseen ops).  Returns ``{}`` when there is no usable signal or no
    differentiation is possible (e.g. a pure bitwise-only op set, where the
    constant/mask machinery — not the operator mix — carries the signal).

    Signals (all O(N·D) on a ≤``max_rows`` subsample, robust to subsampling):
      • per-feature transform correlations — the |corr(f(x_i), y)| of each
        candidate transform becomes evidence for the operator(s) it implies
        (square/cube/sqrt/log/inv/exp/sin/cos/tanh/abs/gauss/sign);
      • pairwise product / ratio correlations reinforce ``*`` and ``/``;
      • global target-shape cues — integer-valued targets favour bit/integer
        ops (only when arithmetic ops coexist, so the steer is informative),
        bounded targets favour sigmoid / tanh, sign-changing targets favour
        the odd/signed families.
    """
    ops_all = list(getattr(CGPEquation, 'OPS_ALL', []) or [])
    if not ops_all:
        return {}
    allowed = set(ops_all)
    # A pure bit-twiddling op set offers no operator-level signal to exploit
    # (all families are bitwise); de-novo gains there come from the mask/const
    # machinery instead, so skip and leave operator selection uniform.
    _non_bitwise = allowed - {'bitwise_and', 'bitwise_or', 'bitwise_xor',
                              'bitwise_not', 'lshift', 'rshift', 'const'}
    if not _non_bitwise:
        return {}
    try:
        y = np.asarray(y, dtype=np.float64).ravel()
        X = np.asarray(X, dtype=np.float64)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
    except Exception:
        return {}
    N = y.shape[0]
    if N < 8 or X.shape[0] != N:
        return {}
    if N > max_rows:
        # With-replacement subsample: cheaper than a replace=False permutation
        # for large N, and a few duplicate rows don't change a correlation
        # estimate.  This keeps the per-chunk prior recompute negligible even
        # on big datasets.
        idx = np.random.randint(0, N, size=max_rows)
        Xs, ys = X[idx], y[idx]
    else:
        Xs, ys = X, y
    finite_y = np.isfinite(ys)
    if int(np.sum(finite_y)) < 8:
        return {}
    ys = np.where(finite_y, ys, 0.0)
    if float(np.std(ys)) < 1e-12:
        return {}

    score: dict = {}

    def bump(op, amt):
        # Record the *strongest* evidence seen for an op (max, not sum) so a
        # family that correlates well through one transform isn't diluted by
        # weaker transforms that happen to map to the same op.
        if op in allowed and amt > 0.0 and np.isfinite(amt):
            score[op] = max(score.get(op, 0.0), float(amt))

    def _safe_corr(a, b):
        try:
            if np.std(a) < 1e-10:
                return 0.0
            r = float(np.corrcoef(a, b)[0, 1])
            return abs(r) if np.isfinite(r) else 0.0
        except Exception:
            return 0.0

    # ── Global target-shape cues ─────────────────────────────────────────
    y_min, y_max = float(np.min(ys)), float(np.max(ys))
    has_neg = y_min < -1e-9
    has_pos = y_max > 1e-9
    sign_change = has_neg and has_pos

    # Integer target + arithmetic ops present → discrete / bit operators.
    if detect_integer_target(ys):
        for op in ('bitwise_and', 'bitwise_or', 'bitwise_xor', 'bitwise_not',
                   'lshift', 'rshift', 'mod', 'floor', 'round', 'gcd',
                   'digit_sum'):
            bump(op, 0.85)

    # Bounded targets → squashing nonlinearities.
    if -1e-6 <= y_min and y_max <= 1.0 + 1e-6 and (y_max - y_min) > 0.2:
        bump('sigmoid', 0.8)
    if -1.0 - 1e-6 <= y_min and y_max <= 1.0 + 1e-6 and sign_change:
        bump('tanh', 0.8)
        bump('erf', 0.6)

    if sign_change:
        bump('neg', 0.45)
        bump('sign', 0.45)
        bump('cube', 0.45)
    else:
        if has_pos and not has_neg:
            bump('relu', 0.45)
            bump('abs', 0.4)
            bump('square', 0.4)

    # ── Per-feature transform correlations (richest signal) ──────────────
    # NOTE: sin/cos are handled by a dedicated frequency sweep below, not here.
    # A single-frequency sin(x) probe is near-orthogonal to a sin(2x)/cos(3x)
    # target, so it scored genuinely periodic data at the 0.3 baseline and the
    # search got no steer toward the trig family at all.
    transforms = [
        ('square', lambda v: v * v,                       ('square', 'pow')),
        ('cube',   lambda v: v * v * v,                   ('cube', 'pow')),
        ('sqrt',   lambda v: np.sqrt(np.abs(v)),          ('sqrt',)),
        ('log',    lambda v: np.log(np.abs(v) + 1e-30),   ('log',)),
        ('inv',    lambda v: 1.0 / (np.abs(v) + 1e-8),    ('/',)),
        ('exp',    lambda v: np.exp(np.clip(v, -30, 30)), ('exp',)),
        ('tanh',   lambda v: np.tanh(v),                  ('tanh', 'sigmoid')),
        ('abs',    lambda v: np.abs(v),                   ('abs',)),
        ('gauss',  lambda v: np.exp(-np.clip(v * v, 0, 60)), ('gaussian',)),
        ('sign',   lambda v: np.sign(v),                  ('sign',)),
    ]
    # Angular frequencies swept for periodic detection (see note above the
    # transforms list).  Includes ω=1, so this is a strict superset of the
    # legacy single-frequency probe — it never weakens sin/cos detection on a
    # target the baseline already caught, it only ADDS detection for higher-
    # frequency periodicity (sin(2x), cos(3x), …) the ω=1 probe was blind to.
    _trig_omegas = (0.5, 1.0, 1.5, 2.0, 3.0)
    n_feat = Xs.shape[1]
    for i in range(n_feat):
        xi = Xs[:, i]
        if np.std(xi) < 1e-10:
            continue
        rl = _safe_corr(xi, ys)
        if rl > 0:
            # Linear correlation feeds the additive/scaling backbone.
            bump('+', 0.3 + 0.5 * rl)
            bump('-', 0.3 + 0.5 * rl)
            bump('*', 0.3 + 0.4 * rl)
        for _name, fn, mapped in transforms:
            try:
                xf = np.nan_to_num(fn(xi), nan=0.0, posinf=0.0, neginf=0.0)
            except Exception:
                continue
            r = _safe_corr(xf, ys)
            if r > 0:
                for op in mapped:
                    bump(op, r)
        # Frequency-swept periodic probe → sin/cos (see note above).  Keep the
        # strongest correlation across the sweep and bump on any positive
        # signal, exactly mirroring how every other transform votes — so a
        # genuinely periodic target (at any of the swept frequencies) gets the
        # trig steer it was previously denied, while non-periodic data behaves
        # as it did under the legacy ω=1 sin/cos transform.
        _rp = 0.0
        for _w in _trig_omegas:
            try:
                _rp = max(_rp, _safe_corr(np.sin(_w * xi), ys),
                          _safe_corr(np.cos(_w * xi), ys))
            except Exception:
                continue
        if _rp > 0:
            bump('sin', _rp)
            bump('cos', _rp)

    # ── Pairwise product / ratio → reinforce * and / ─────────────────────
    if n_feat >= 2:
        cols = list(range(n_feat))
        random.shuffle(cols)
        cols = cols[:min(6, n_feat)]
        for a in cols:
            xa = Xs[:, a]
            if np.std(xa) < 1e-10:
                continue
            for b in cols:
                if b <= a:
                    continue
                xb = Xs[:, b]
                if np.std(xb) < 1e-10:
                    continue
                try:
                    pr = np.nan_to_num(xa * xb, nan=0.0, posinf=0.0, neginf=0.0)
                    bump('*', _safe_corr(pr, ys))
                    rt = np.nan_to_num(xa / (np.abs(xb) + 1e-8),
                                       nan=0.0, posinf=0.0, neginf=0.0)
                    bump('/', _safe_corr(rt, ys))
                except Exception:
                    pass

    if not score:
        return {}
    mx = max(score.values())
    if mx <= 0:
        return {}

    prior = {}
    for op in ops_all:
        prior[op] = max(0.3, min(1.0, score.get(op, 0.0) / mx))
    # Constants are needed by almost every expression (coefficients, masks,
    # thresholds) but rarely correlate with the target on their own, so the
    # transform scan never votes for them — give them a fixed floor.  The
    # additive/multiplicative staples are deliberately *not* floored: doing so
    # dilutes the prior's emphasis on the target's actual nonlinearities (which
    # is the whole signal), and the 0.3 baseline plus the max-blend with the
    # HoF affinity already keep them comfortably in play.
    if 'const' in allowed:
        prior['const'] = max(prior.get('const', 0.0), 0.55)
    return prior


# ==========================================
# MODULE-LEVEL OP DISPATCH TABLES
# Centralizes all operation logic; evaluate(), __str__,
# get_complexity(), and tree_to_sympy() all pull from here.
# ==========================================

# ==========================================
# SAFE / UNSAFE OP IMPLEMENTATIONS
# ==========================================
#
# SAFE MODE  — every operation is total: domain violations are deflected by
#              input clamping, abs-wrapping, or epsilon guards so that no NaN
#              or Inf can ever escape a node.  Evolution is stable.  In SAFE
#              mode `exp` is the real exponential with its argument clamped
#              to [-700, 700] (preventing overflow without changing the
#              function's meaning); the previous comment claimed it became
#              `exp(-|v|)`, which never matched the implementation.
#
# UNSAFE MODE — raw numpy semantics.  Domain violations (log of negative,
#              sqrt of negative, div-by-zero, exp overflow …) produce NaN/Inf,
#              which are caught by the nan_to_num call in CGPEquation.evaluate()
#              and clamped to 0 / ±1e9.  Expressions are mathematically purer
#              and exp is the real exponential, but evolution is noisier because
#              large sub-trees can temporarily collapse to zero or ±1e9.
#
# Toggle with SAFE_OPS_MODE (set by select_ops_safety() in train_mode).
# ==========================================

SAFE_OPS_MODE = True  # default; changed interactively at startup

# ---- Affine Scaling ----
# When enabled (default), every regression individual gets an analytic
# affine rescaling y = a*f(x) + b, fitted once on the full dataset.
# This lets the evolutionary search focus on shape rather than scale.
# Disabling forces the CGP to learn scale/offset from constants alone.
AFFINE_SCALING_ENABLED = True

# When True, the locked affine (a, b) is refined past its ordinary-least-squares
# seed with a few IRLS (iteratively-reweighted least-squares) passes whose
# pseudo-Huber weights live in the SAME standardised residual units — r/std(y),
# knee ROBUST_LOSS_HUBER_DELTA — as the robust regression_loss().  Rationale: the
# affine is the "finetune the magnitude" half of the shape→magnitude split, but
# plain OLS minimises SQUARED error while the model is SELECTED on the robust
# loss, so on heavy-tailed targets (the chaotic mod/floor/bitwise outputs this
# engine handles) a few rows drag the OLS slope/offset off and the magnitude
# finetune ends up fighting the very score that ranks it.  The IRLS refit
# down-weights those rows so the affine optimises the objective it is judged on.
# The OLS result is the warm start and whichever of {OLS, IRLS} scores the lower
# regression_loss is kept, so the robust fit can NEVER be worse than the legacy
# one by its own objective.  No effect under REGRESSION_LOSS_MODE="mse_mae" (OLS
# already minimises that pure-squared loss) or when affine scaling is off.
AFFINE_ROBUST_FIT       = True
AFFINE_ROBUST_FIT_ITERS = 3      # IRLS passes past the OLS seed (each O(N); 0 ⇒ OLS only)

# ---- helpers used by SAFE variants ----
def _sinc_fn(v):
    mask = np.abs(v) > 1e-8
    return np.where(mask, np.sin(v) / np.where(mask, v, 1.0), 1.0)

def _erf_fn(v):
    if HAS_SCIPY_SPECIAL:
        return scipy_special.erf(v)
    return np.tanh(np.clip(1.2 * v, -20, 20))


# ─────────────────────────────────────────────────────────────────────────────
# Helpers for newer operators (bitwise, RNG, noise, digit ops, perceptrons …)
# ─────────────────────────────────────────────────────────────────────────────
# Floats are converted to bounded int64 first so the bit operations do not
# overflow or produce NaN.  All helpers are pure functions; vectorised over
# numpy arrays so they slot straight into BINARY_OPS_EVAL / UNARY_OPS_EVAL.

_INT_OP_CLAMP = 1e15  # cap before int conversion — keeps bitwise ops in int64 range
_FLOAT_BITS_CLAMP = 1e9   # NaN/±Inf clamp for raw-float bitwise results; matches the
                          # per-node sanitiser in CGPEquation.evaluate() so a model
                          # evolved in float-bitwise mode exports bit-for-bit identically

# How bitwise / shift operators (bitwise_and/or/xor/not, lshift, rshift) treat
# their operands.  Set interactively in train_mode() via _select_bitwise_mode():
#   'int'   — floor + clip each operand to a bounded int64, then bit-twiddle
#             (RNG / hashing / digit-style equations).  This is the default and
#             preserves the original behaviour.
#   'float' — apply the bit operation directly to the raw 8 bytes (IEEE-754 bit
#             pattern) of each float64 operand, reinterpreting the result bytes
#             back as a float64 (no value→int rounding).
BITWISE_MODE = 'int'


def _to_int(v):
    """Clamp + floor + cast to int64 for bitwise / digit operations."""
    return np.floor(np.clip(np.nan_to_num(v, nan=0.0, posinf=_INT_OP_CLAMP,
                                          neginf=-_INT_OP_CLAMP),
                            -_INT_OP_CLAMP, _INT_OP_CLAMP)).astype(np.int64)


def _float_to_bits(v):
    """Reinterpret float64 values as their raw uint64 IEEE-754 bit-pattern.

    This is a pure type-pun (a ``view``), not a value conversion: 1.0 becomes
    0x3FF0000000000000, not 1.  Used by the 'float' bitwise mode so the bit
    operators scramble the actual exponent/mantissa bytes of the operands.
    """
    return np.ascontiguousarray(v, dtype=np.float64).view(np.uint64)


def _bits_to_float(b):
    """Reinterpret a uint64 bit-pattern back to float64, then sanitise NaN/±Inf
    to 0.0 / ±_FLOAT_BITS_CLAMP.  Many bit patterns decode to NaN/Inf, so this
    mirrors the per-node clamp applied in CGPEquation.evaluate() — keeping live
    evaluation and the exported script numerically identical.
    """
    out = np.ascontiguousarray(b, dtype=np.uint64).view(np.float64)
    return np.nan_to_num(out, nan=0.0, posinf=_FLOAT_BITS_CLAMP,
                         neginf=-_FLOAT_BITS_CLAMP)


def _bitwise_and(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_and(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_and(_to_int(v1), _to_int(v2)).astype(np.float64)
def _bitwise_or(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_or(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_or(_to_int(v1), _to_int(v2)).astype(np.float64)
def _bitwise_xor(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_xor(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_xor(_to_int(v1), _to_int(v2)).astype(np.float64)
def _bitwise_not(v):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_not(_float_to_bits(v)))
    return np.bitwise_not(_to_int(v)).astype(np.float64)
def _lshift(v1, v2):
    if BITWISE_MODE == 'float':
        s = np.clip(_to_int(v2), 0, 63).astype(np.uint64)
        return _bits_to_float(np.left_shift(_float_to_bits(v1), s))
    a = _to_int(v1)
    s = np.clip(_to_int(v2), 0, 62)
    return np.left_shift(a, s).astype(np.float64)
def _rshift(v1, v2):
    if BITWISE_MODE == 'float':
        s = np.clip(_to_int(v2), 0, 63).astype(np.uint64)
        return _bits_to_float(np.right_shift(_float_to_bits(v1), s))
    a = _to_int(v1)
    s = np.clip(_to_int(v2), 0, 62)
    return np.right_shift(a, s).astype(np.float64)


def _bitwise_ops_source(mode):
    """Return Python source (as text) for the bitwise / shift operator helpers
    used by *exported* model scripts — the ``_op_*`` names emitted by
    tree_to_python_expr.  ``mode`` ('int' or 'float') is baked into the generated
    file as a module constant so an exported model computes bit-for-bit
    identically to the live evolver that produced it.  The bodies are deliberately
    the same logic as the live ``_bitwise_*`` helpers above.
    """
    return f'''_INT_OP_CLAMP = 1e15
_FLOAT_BITS_CLAMP = 1e9
BITWISE_MODE = {mode!r}
def _to_int(v):
    return np.floor(np.clip(np.nan_to_num(v, nan=0.0, posinf=_INT_OP_CLAMP,
                                          neginf=-_INT_OP_CLAMP),
                            -_INT_OP_CLAMP, _INT_OP_CLAMP)).astype(np.int64)
def _float_to_bits(v):
    return np.ascontiguousarray(v, dtype=np.float64).view(np.uint64)
def _bits_to_float(b):
    out = np.ascontiguousarray(b, dtype=np.uint64).view(np.float64)
    return np.nan_to_num(out, nan=0.0, posinf=_FLOAT_BITS_CLAMP, neginf=-_FLOAT_BITS_CLAMP)
def _op_bitwise_and(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_and(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_and(_to_int(v1), _to_int(v2)).astype(np.float64)
def _op_bitwise_or(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_or(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_or(_to_int(v1), _to_int(v2)).astype(np.float64)
def _op_bitwise_xor(v1, v2):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_xor(_float_to_bits(v1), _float_to_bits(v2)))
    return np.bitwise_xor(_to_int(v1), _to_int(v2)).astype(np.float64)
def _op_bitwise_not(v):
    if BITWISE_MODE == 'float':
        return _bits_to_float(np.bitwise_not(_float_to_bits(v)))
    return np.bitwise_not(_to_int(v)).astype(np.float64)
def _op_lshift(v1, v2):
    if BITWISE_MODE == 'float':
        s = np.clip(_to_int(v2), 0, 63).astype(np.uint64)
        return _bits_to_float(np.left_shift(_float_to_bits(v1), s))
    return np.left_shift(_to_int(v1), np.clip(_to_int(v2), 0, 62)).astype(np.float64)
def _op_rshift(v1, v2):
    if BITWISE_MODE == 'float':
        s = np.clip(_to_int(v2), 0, 63).astype(np.uint64)
        return _bits_to_float(np.right_shift(_float_to_bits(v1), s))
    return np.right_shift(_to_int(v1), np.clip(_to_int(v2), 0, 62)).astype(np.float64)'''


def _ne(v1, v2):           return np.where(v1 != v2, 1.0, 0.0)


def _round2(v1, v2):
    # round to n decimals; cap n to a sane range
    n = np.clip(_to_int(v2), -15, 15)
    f = np.power(10.0, n.astype(np.float64))
    return np.round(v1 * f) / f
def _floor2(v1, v2):
    n = np.clip(_to_int(v2), -15, 15)
    f = np.power(10.0, n.astype(np.float64))
    return np.floor(v1 * f) / f
def _ceil2(v1, v2):
    n = np.clip(_to_int(v2), -15, 15)
    f = np.power(10.0, n.astype(np.float64))
    return np.ceil(v1 * f) / f


def _quantize(v1, v2):
    # round(v1 / step) * step, with step guarded against zero
    step = np.where(np.abs(v2) > 1e-12, v2, 1.0)
    return np.round(v1 / step) * step


def _gcd(v1, v2):
    a = np.abs(_to_int(v1))
    b = np.abs(_to_int(v2))
    return np.gcd(a, b).astype(np.float64)


def _lcm(v1, v2):
    a = np.abs(_to_int(v1))
    b = np.abs(_to_int(v2))
    g = np.gcd(a, b)
    g_safe = np.where(g == 0, 1, g)
    return (np.abs(a // g_safe * b)).astype(np.float64)


def _cat(v1, v2):
    """Concatenate two values as decimal digits: cat(12, 34) → 1234."""
    a = np.abs(_to_int(v1))
    b = np.abs(_to_int(v2))
    b_safe = np.maximum(b, 1)
    digits = np.minimum(
        9,
        (np.floor(np.log10(b_safe.astype(np.float64) + 1e-30)) + 1).astype(np.int64))
    digits = np.where(b == 0, 1, digits)
    factor = np.power(10.0, digits.astype(np.float64))
    return a.astype(np.float64) * factor + b.astype(np.float64)


def _x_at_pos_y_scalar(x, y):
    if not np.isfinite(x) or not np.isfinite(y):
        return -1.0
    text = repr(float(x))
    pos = int(y)
    if pos < 0 or pos >= len(text):
        return -1.0
    ch = text[pos]
    return float(ch) if ch.isdigit() else -1.0


_x_at_pos_y_vec = np.vectorize(_x_at_pos_y_scalar, otypes=[np.float64])
def _x_at_pos_y(v1, v2): return _x_at_pos_y_vec(v1, v2)


def _python_rng_scalar(x):
    if not np.isfinite(x):
        return 0.0
    try:
        return random.Random(int(x)).random()
    except (OverflowError, ValueError):
        return 0.0


_python_rng_vec = np.vectorize(_python_rng_scalar, otypes=[np.float64])
def _python_rng(v): return _python_rng_vec(v)


def _signbit(v):
    return np.where(np.signbit(np.nan_to_num(v, nan=0.0)), 1.0, 0.0)


def _deg2rad(v): return v * (np.pi / 180.0)
def _rad2deg(v): return v * (180.0 / np.pi)


def _pow_k_factory(k):
    """Return a fast lambda implementing v**k (cheap, no overflow guards)."""
    return lambda v: np.power(v, k)


def _perlin_noise_1d(v):
    """1-D value noise with smoothstep — Perlin-like aesthetic, no scipy dep."""
    v_clip = np.clip(np.nan_to_num(v, nan=0.0), -1e6, 1e6)
    floor_v = np.floor(v_clip).astype(np.int64)
    frac = v_clip - floor_v

    def _hash01(n):
        n_u = (n.astype(np.int64) & np.int64(0xFFFFFFFF))
        n_u = (n_u * np.int64(0x27d4eb2d)) & np.int64(0xFFFFFFFF)
        n_u = (n_u ^ (n_u >> 13)) & np.int64(0xFFFFFFFF)
        n_u = (n_u * np.int64(0x85ebca6b)) & np.int64(0xFFFFFFFF)
        return n_u.astype(np.float64) / float(0xFFFFFFFF) * 2.0 - 1.0

    g0 = _hash01(floor_v)
    g1 = _hash01(floor_v + 1)
    t = frac * frac * (3.0 - 2.0 * frac)
    return g0 * (1.0 - t) + g1 * t


# ---- Perceptron-style activations (gated behind an interactive prompt) ----
def _perc_sigma1(v):
    return 1.0 / (1.0 + np.exp(-np.clip(v, -50.0, 50.0)))
def _perc_relu1(v):
    return np.maximum(0.0, v)
def _perc_custom1(v):
    # Swish: x * sigmoid(x) — smooth, non-monotonic, "novel" activation.
    return v / (1.0 + np.exp(-np.clip(v, -50.0, 50.0)))
def _perc_sigma2(v1, v2):
    s = v1 + v2
    return 1.0 / (1.0 + np.exp(-np.clip(s, -50.0, 50.0)))
def _perc_relu2(v1, v2):
    return np.maximum(0.0, v1 + v2)
def _perc_custom2(v1, v2):
    s = v1 + v2
    return s / (1.0 + np.exp(-np.clip(s, -50.0, 50.0)))


