    _select_perceptron_mode()

    # ---- Operator selection ----
    select_allowed_ops()

    # ---- Bitwise operand mode (int-coerced vs raw float bytes) ----
    _select_bitwise_mode()

    # ---- IF/ELSE branching (separate from operator selection) ----
    _select_if_else_mode()

    # ---- Gradient boosting mode ----
    _select_gradient_boosting()

    # ---- Class-imbalance handling ----
    _select_class_weight_mode()

    # ---- Per-example difficulty weighting (optional hard-example mining) ----
